			}
			foreach (InputBinding @override in overrides)
			{
				actionMap.ApplyBindingOverride(@override);
			}
		}

		public static void RemoveBindingOverrides(this InputActionMap actionMap, IEnumerable<InputBinding> overrides)
		{
