		public bool isComposite
		{
			get
			{
				return (m_Flags & Flags.Composite) == Flags.Composite;
			}
			set
			{
				if (value)
				{
					m_Flags |= Flags.Composite;
				}
				else
				{
					m_Flags &= ~Flags.Composite;
				}
			}
		}

		public bool isPartOfComposite
		{
