		{
			TDevice val = null;
			double num = -1.0;
			foreach (InputDevice device in devices)
			{
				if (device is TDevice val2 && val2.usages.Contains(usage) && (val == null || val2.m_LastUpdateTimeInternal > num))
				{
					val = val2;
					num = val.m_LastUpdateTimeInternal;
				}
			}
			return val;
		}

