		internal enum ControlFlags
		{
			ConfigUpToDate = 1,
			IsNoisy = 2,
			IsSynthetic = 4,
			IsButton = 8,
			DontReset = 0x10,
			SetupFinished = 0x20,
			UsesStateFromOtherControl = 0x40
		}

		protected internal InputStateBlock m_StateBlock;

		internal InternedString m_Name;

		internal string m_Path;

