		private string DebuggerDisplay()
		{
			if (!device.added)
			{
				return ToString();
			}
			try
			{
				return $"{layout}:{path}={this.ReadValueAsObject()}";
			}
			catch (Exception)
			{
				return ToString();
			}
		}

