	public abstract class OnScreenControl : MonoBehaviour
	{
		private struct OnScreenDeviceInfo
		{
			public InputEventPtr eventPtr;

			public NativeArray<byte> buffer;

			public InputDevice device;

			public OnScreenControl firstControl;

			public OnScreenDeviceInfo AddControl(OnScreenControl control)
			{
				control.m_NextControlOnDevice = firstControl;
				firstControl = control;
				return this;
			}

			public OnScreenDeviceInfo RemoveControl(OnScreenControl control)
			{
				if (firstControl == control)
				{
					firstControl = control.m_NextControlOnDevice;
				}
				else
				{
					OnScreenControl nextControlOnDevice = firstControl.m_NextControlOnDevice;
					OnScreenControl onScreenControl = firstControl;
					while (nextControlOnDevice != null)
					{
						if (!(nextControlOnDevice != control))
						{
							onScreenControl.m_NextControlOnDevice = nextControlOnDevice.m_NextControlOnDevice;
							break;
						}
						onScreenControl = nextControlOnDevice;
						nextControlOnDevice = nextControlOnDevice.m_NextControlOnDevice;
					}
				}
				control.m_NextControlOnDevice = null;
				return this;
			}

			public void Destroy()
			{
				if (buffer.IsCreated)
				{
					buffer.Dispose();
				}
				if (device != null)
				{
					InputSystem.RemoveDevice(device);
				}
				device = null;
				buffer = default(NativeArray<byte>);
			}
		}

		private InputControl m_Control;

		private OnScreenControl m_NextControlOnDevice;

		private InputEventPtr m_InputEventPtr;

		private static int s_nbActiveInstances;

		private static InlinedArray<OnScreenDeviceInfo> s_OnScreenDevices;

		public string controlPath
		{
			get
			{
				return controlPathInternal;
			}
			set
			{
				controlPathInternal = value;
				if (base.isActiveAndEnabled)
				{
					SetupInputControl();
				}
			}
		}

		public InputControl control => m_Control;

		protected abstract string controlPathInternal { get; set; }

		internal static bool HasAnyActive => s_nbActiveInstances != 0;

		private void SetupInputControl()
		{
			string text = controlPathInternal;
			if (string.IsNullOrEmpty(text))
			{
				return;
			}
			string text2 = InputControlPath.TryGetDeviceLayout(text);
			if (text2 == null)
			{
				Debug.LogError("Cannot determine device layout to use based on control path '" + text + "' used in " + GetType().Name + " component", this);
				return;
			}
			InternedString internedString = new InternedString(text2);
			int num = -1;
			for (int i = 0; i < s_OnScreenDevices.length; i++)
			{
				if (s_OnScreenDevices[i].device.m_Layout == internedString)
				{
					num = i;
					break;
				}
			}
			InputDevice device;
			if (num == -1)
			{
				try
				{
					device = InputSystem.AddDevice(text2);
				}
				catch (Exception exception)
				{
					Debug.LogError("Could not create device with layout '" + text2 + "' used in '" + GetType().Name + "' component");
					Debug.LogException(exception);
					return;
				}
				InputSystem.AddDeviceUsage(device, "OnScreen");
				InputEventPtr eventPtr;
				NativeArray<byte> buffer = StateEvent.From(device, out eventPtr, Allocator.Persistent);
				num = s_OnScreenDevices.Append(new OnScreenDeviceInfo
				{
					eventPtr = eventPtr,
					buffer = buffer,
					device = device
				});
			}
			else
			{
				device = s_OnScreenDevices[num].device;
			}
			m_Control = InputControlPath.TryFindControl(device, text);
			if (m_Control == null)
			{
				Debug.LogError("Cannot find control with path '" + text + "' on device of type '" + text2 + "' referenced by component '" + GetType().Name + "'", this);
				if (s_OnScreenDevices[num].firstControl == null)
				{
					s_OnScreenDevices[num].Destroy();
					s_OnScreenDevices.RemoveAt(num);
				}
			}
			else
			{
				m_InputEventPtr = s_OnScreenDevices[num].eventPtr;
				s_OnScreenDevices[num] = s_OnScreenDevices[num].AddControl(this);
			}
		}

		protected void SendValueToControl<TValue>(TValue value) where TValue : struct
		{
			if (m_Control != null)
			{
				if (!(m_Control is InputControl<TValue> inputControl))
				{
					throw new ArgumentException("The control path " + controlPath + " yields a control of type " + m_Control.GetType().Name + " which is not an InputControl with value type " + typeof(TValue).Name, "value");
				}
				m_InputEventPtr.internalTime = InputRuntime.s_Instance.currentTime;
				inputControl.WriteValueIntoEvent(value, m_InputEventPtr);
				InputSystem.QueueEvent(m_InputEventPtr);
			}
		}

		protected void SentDefaultValueToControl()
		{
			if (m_Control != null)
			{
				m_InputEventPtr.internalTime = InputRuntime.s_Instance.currentTime;
				m_Control.ResetToDefaultStateInEvent(m_InputEventPtr);
				InputSystem.QueueEvent(m_InputEventPtr);
			}
		}

		protected virtual void OnEnable()
		{
			s_nbActiveInstances++;
			SetupInputControl();
			if (m_Control == null || s_nbActiveInstances != 1 || !PlayerInput.isSinglePlayer)
			{
				return;
			}
			PlayerInput playerByIndex = PlayerInput.GetPlayerByIndex(0);
			if ((object)playerByIndex == null || playerByIndex.neverAutoSwitchControlSchemes)
			{
				return;
			}
			ReadOnlyArray<InputDevice> devices = playerByIndex.devices;
			bool flag = false;
			foreach (InputDevice item in devices)
			{
				if (m_Control.device.deviceId == item.deviceId)
				{
					flag = true;
					break;
				}
			}
			if (!flag)
			{
				playerByIndex.SwitchCurrentControlScheme(m_Control.device);
			}
		}

		protected virtual void OnDisable()
		{
			s_nbActiveInstances--;
			if (m_Control == null)
			{
				return;
			}
			InputDevice device = m_Control.device;
			for (int i = 0; i < s_OnScreenDevices.length; i++)
			{
				if (s_OnScreenDevices[i].device != device)
				{
					continue;
				}
				OnScreenDeviceInfo value = s_OnScreenDevices[i].RemoveControl(this);
				if (value.firstControl == null)
				{
					s_OnScreenDevices[i].Destroy();
					s_OnScreenDevices.RemoveAt(i);
				}
				else
				{
					s_OnScreenDevices[i] = value;
					if (!m_Control.CheckStateIsAtDefault())
					{
						SentDefaultValueToControl();
					}
				}
				m_Control = null;
				m_InputEventPtr = default(InputEventPtr);
				break;
			}
		}

		internal string GetWarningMessage()
		{
			return $"{GetType()} needs to be attached as a child to a UI Canvas and have a RectTransform component to function properly.";
		}
	}
	internal static class UGUIOnScreenControlUtils
	{
		public static RectTransform GetCanvasRectTransform(Transform transform)
		{
			if (!(transform.parent != null))
			{
				return null;
			}
			return transform.parent.GetComponentInParent<RectTransform>();
		}
	}
	[AddComponentMenu("Input/On-Screen Stick")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.inputsystem@1.14/manual/OnScreen.html#on-screen-sticks")]
	public class OnScreenStick : OnScreenControl, IPointerDownHandler, IEventSystemHandler, IPointerUpHandler, IDragHandler
	{
		public enum Behaviour
		{
			RelativePositionWithStaticOrigin,
			ExactPositionWithStaticOrigin,
			ExactPositionWithDynamicOrigin
		}

		private const string kDynamicOriginClickable = "DynamicOriginClickable";

		[FormerlySerializedAs("movementRange")]
		[SerializeField]
		[Min(0f)]
		private float m_MovementRange = 50f;

		[SerializeField]
		[Tooltip("Defines the circular region where the onscreen control may have it's origin placed.")]
		[Min(0f)]
		private float m_DynamicOriginRange = 100f;

		[InputControl(layout = "Vector2")]
		[SerializeField]
		private string m_ControlPath;

		[SerializeField]
		[Tooltip("Choose how the onscreen stick will move relative to it's origin and the press position.\n\nRelativePositionWithStaticOrigin: The control's center of origin is fixed. The control will begin un-actuated at it's centered position and then move relative to the pointer or finger motion.\n\nExactPositionWithStaticOrigin: The control's center of origin is fixed. The stick will immediately jump to the exact position of the click or touch and begin tracking motion from there.\n\nExactPositionWithDynamicOrigin: The control's center of origin is determined by the initial press position. The stick will begin un-actuated at this center position and then track the current pointer or finger position.")]
		private Behaviour m_Behaviour;

		[SerializeField]
		[Tooltip("Set this to true to prevent cancellation of pointer events due to device switching. Cancellation will appear as the stick jumping back and forth between the pointer position and the stick center.")]
		private bool m_UseIsolatedInputActions;

		[SerializeField]
		[Tooltip("The action that will be used to detect pointer down events on the stick control. Note that if no bindings are set, default ones will be provided.")]
		private InputAction m_PointerDownAction;

		[SerializeField]
		[Tooltip("The action that will be used to detect pointer movement on the stick control. Note that if no bindings are set, default ones will be provided.")]
		private InputAction m_PointerMoveAction;

		private Vector3 m_StartPos;

		private Vector2 m_PointerDownPos;

		[NonSerialized]
		private List<RaycastResult> m_RaycastResults;

		[NonSerialized]
		private PointerEventData m_PointerEventData;

		[NonSerialized]
		private TouchControl m_TouchControl;

		[NonSerialized]
		private bool m_IsIsolationActive;

		public float movementRange
		{
			get
			{
				return m_MovementRange;
			}
			set
			{
				m_MovementRange = value;
			}
		}

		public float dynamicOriginRange
		{
			get
			{
				return m_DynamicOriginRange;
			}
			set
			{
				if (m_DynamicOriginRange != value)
				{
					m_DynamicOriginRange = value;
					UpdateDynamicOriginClickableArea();
				}
			}
		}

		public bool useIsolatedInputActions
		{
			get
			{
				return m_UseIsolatedInputActions;
			}
			set
			{
				m_UseIsolatedInputActions = value;
			}
		}

		protected override string controlPathInternal
		{
			get
			{
				return m_ControlPath;
			}
			set
			{
				m_ControlPath = value;
			}
		}

		public Behaviour behaviour
		{
			get
			{
				return m_Behaviour;
			}
			set
			{
				m_Behaviour = value;
			}
		}

		public void OnPointerDown(PointerEventData eventData)
		{
			if (!m_UseIsolatedInputActions)
			{
				if (eventData == null)
				{
					throw new ArgumentNullException("eventData");
				}
				BeginInteraction(eventData.position, eventData.pressEventCamera);
			}
		}

		public void OnDrag(PointerEventData eventData)
		{
			if (!m_UseIsolatedInputActions)
			{
				if (eventData == null)
				{
					throw new ArgumentNullException("eventData");
				}
				MoveStick(eventData.position, eventData.pressEventCamera);
			}
		}

		public void OnPointerUp(PointerEventData eventData)
		{
			if (!m_UseIsolatedInputActions)
			{
				EndInteraction();
			}
		}

		private void Start()
		{
			if (m_UseIsolatedInputActions)
			{
				m_RaycastResults = new List<RaycastResult>();
				m_PointerEventData = new PointerEventData(EventSystem.current);
				if (m_PointerDownAction == null || m_PointerDownAction.bindings.Count == 0)
				{
					if (m_PointerDownAction == null)
					{
						m_PointerDownAction = new InputAction(null, InputActionType.PassThrough);
					}
					else if (m_PointerDownAction.m_Type != InputActionType.PassThrough)
					{
						m_PointerDownAction.m_Type = InputActionType.PassThrough;
					}
					m_PointerDownAction.AddBinding("<Mouse>/leftButton");
					m_PointerDownAction.AddBinding("<Pen>/tip");
					m_PointerDownAction.AddBinding("<Touchscreen>/touch*/press");
					m_PointerDownAction.AddBinding("<XRController>/trigger");
				}
				if (m_PointerMoveAction == null || m_PointerMoveAction.bindings.Count == 0)
				{
					if (m_PointerMoveAction == null)
					{
						m_PointerMoveAction = new InputAction();
					}
					m_PointerMoveAction.AddBinding("<Mouse>/position");
					m_PointerMoveAction.AddBinding("<Pen>/position");
					m_PointerMoveAction.AddBinding("<Touchscreen>/touch*/position");
				}
				m_PointerDownAction.performed += OnPointerChanged;
				m_PointerDownAction.Enable();
				m_PointerMoveAction.Enable();
			}
			if (base.transform is RectTransform)
			{
				m_StartPos = ((RectTransform)base.transform).anchoredPosition;
				if (m_Behaviour == Behaviour.ExactPositionWithDynamicOrigin)
				{
					m_PointerDownPos = m_StartPos;
					GameObject obj = new GameObject("DynamicOriginClickable", typeof(UnityEngine.UI.Image));
					obj.transform.SetParent(base.transform);
					UnityEngine.UI.Image component = obj.GetComponent<UnityEngine.UI.Image>();
					component.color = new Color(1f, 1f, 1f, 0f);
					RectTransform obj2 = (RectTransform)obj.transform;
					obj2.sizeDelta = new Vector2(m_DynamicOriginRange * 2f, m_DynamicOriginRange * 2f);
					obj2.localScale = new Vector3(1f, 1f, 0f);
					obj2.anchoredPosition3D = Vector3.zero;
					component.sprite = SpriteUtilities.CreateCircleSprite(16, new Color32(byte.MaxValue, byte.MaxValue, byte.MaxValue, byte.MaxValue));
					component.alphaHitTestMinimumThreshold = 0.5f;
				}
			}
		}

		private void OnDestroy()
		{
			if (m_UseIsolatedInputActions)
			{
				m_PointerDownAction.performed -= OnPointerChanged;
			}
		}

		private void BeginInteraction(Vector2 pointerPosition, Camera uiCamera)
		{
			RectTransform canvasRectTransform = UGUIOnScreenControlUtils.GetCanvasRectTransform(base.transform);
			if (canvasRectTransform == null)
			{
				Debug.LogError(GetWarningMessage());
				return;
			}
			switch (m_Behaviour)
			{
			case Behaviour.RelativePositionWithStaticOrigin:
				RectTransformUtility.ScreenPointToLocalPointInRectangle(canvasRectTransform, pointerPosition, uiCamera, out m_PointerDownPos);
				break;
			case Behaviour.ExactPositionWithStaticOrigin:
				RectTransformUtility.ScreenPointToLocalPointInRectangle(canvasRectTransform, pointerPosition, uiCamera, out m_PointerDownPos);
				MoveStick(pointerPosition, uiCamera);
				break;
			case Behaviour.ExactPositionWithDynamicOrigin:
			{
				RectTransformUtility.ScreenPointToLocalPointInRectangle(canvasRectTransform, pointerPosition, uiCamera, out var localPoint);
				Vector2 pointerDownPos = (((RectTransform)base.transform).anchoredPosition = localPoint);
				m_PointerDownPos = pointerDownPos;
				break;
			}
			}
		}

		private void MoveStick(Vector2 pointerPosition, Camera uiCamera)
		{
			RectTransform canvasRectTransform = UGUIOnScreenControlUtils.GetCanvasRectTransform(base.transform);
			if (canvasRectTransform == null)
			{
				Debug.LogError(GetWarningMessage());
				return;
			}
			RectTransformUtility.ScreenPointToLocalPointInRectangle(canvasRectTransform, pointerPosition, uiCamera, out var localPoint);
			Vector2 vector = localPoint - m_PointerDownPos;
			switch (m_Behaviour)
			{
			case Behaviour.RelativePositionWithStaticOrigin:
				vector = Vector2.ClampMagnitude(vector, movementRange);
				((RectTransform)base.transform).anchoredPosition = (Vector2)m_StartPos + vector;
				break;
			case Behaviour.ExactPositionWithStaticOrigin:
				vector = localPoint - (Vector2)m_StartPos;
				vector = Vector2.ClampMagnitude(vector, movementRange);
				((RectTransform)base.transform).anchoredPosition = (Vector2)m_StartPos + vector;
				break;
			case Behaviour.ExactPositionWithDynamicOrigin:
				vector = Vector2.ClampMagnitude(vector, movementRange);
				((RectTransform)base.transform).anchoredPosition = m_PointerDownPos + vector;
				break;
			}
			Vector2 value = new Vector2(vector.x / movementRange, vector.y / movementRange);
			SendValueToControl(value);
		}

		private void EndInteraction()
		{
			((RectTransform)base.transform).anchoredPosition = (m_PointerDownPos = m_StartPos);
			SendValueToControl(Vector2.zero);
		}

		private void OnPointerDown(InputAction.CallbackContext ctx)
		{
			if (m_IsIsolationActive)
			{
				return;
			}
			Vector2 vector = Vector2.zero;
			TouchControl touchControl = null;
			if (ctx.control?.parent is TouchControl touchControl2)
			{
				touchControl = touchControl2;
				vector = touchControl2.position.ReadValue();
			}
			else if (ctx.control?.device is Pointer pointer)
			{
				vector = pointer.position.ReadValue();
			}
			m_PointerEventData.position = vector;
			EventSystem.current.RaycastAll(m_PointerEventData, m_RaycastResults);
			if (m_RaycastResults.Count == 0)
			{
				return;
			}
			bool flag = false;
			foreach (RaycastResult raycastResult in m_RaycastResults)
			{
				if (!(raycastResult.gameObject != base.gameObject))
				{
					flag = true;
					break;
				}
			}
			if (flag)
			{
				BeginInteraction(vector, GetCameraFromCanvas());
				if (touchControl != null)
				{
					m_TouchControl = touchControl;
					m_PointerMoveAction.ApplyBindingOverride(touchControl.path + "/position", null, "<Touchscreen>/touch*/position");
				}
				m_PointerMoveAction.performed += OnPointerMove;
				m_IsIsolationActive = true;
			}
		}

		private void OnPointerChanged(InputAction.CallbackContext ctx)
		{
			if (ctx.control.IsPressed())
			{
				OnPointerDown(ctx);
			}
			else
			{
				OnPointerUp(ctx);
			}
		}

		private void OnPointerMove(InputAction.CallbackContext ctx)
		{
			Vector2 pointerPosition;
			if (m_TouchControl != null)
			{
				if (!m_TouchControl.isInProgress)
				{
					return;
				}
				pointerPosition = m_TouchControl.position.ReadValue();
			}
			else
			{
				pointerPosition = ((Pointer)ctx.control.device).position.ReadValue();
			}
			MoveStick(pointerPosition, GetCameraFromCanvas());
		}

		private void OnPointerUp(InputAction.CallbackContext ctx)
		{
			if (!m_IsIsolationActive)
			{
				return;
			}
			if (m_TouchControl != null)
			{
				if (m_TouchControl.isInProgress)
				{
					return;
				}
				m_PointerMoveAction.ApplyBindingOverride(null, null, "<Touchscreen>/touch*/position");
				m_TouchControl = null;
			}
			EndInteraction();
			m_PointerMoveAction.performed -= OnPointerMove;
			m_IsIsolationActive = false;
		}

		private Camera GetCameraFromCanvas()
		{
			Canvas componentInParent = GetComponentInParent<Canvas>();
			RenderMode? renderMode = componentInParent?.renderMode;
			if (renderMode != RenderMode.ScreenSpaceOverlay && (renderMode != RenderMode.ScreenSpaceCamera || !(componentInParent?.worldCamera == null)))
			{
				return componentInParent?.worldCamera ?? Camera.main;
			}
			return null;
		}

		private void OnDrawGizmosSelected()
		{
			RectTransform rectTransform = base.transform.parent as RectTransform;
			if (!(rectTransform == null))
			{
				Gizmos.matrix = rectTransform.localToWorldMatrix;
				Vector2 vector = rectTransform.anchoredPosition;
				if (Application.isPlaying)
				{
					vector = m_StartPos;
				}
				Gizmos.color = new Color32(84, 173, 219, byte.MaxValue);
				Vector2 center = vector;
				if (Application.isPlaying && m_Behaviour == Behaviour.ExactPositionWithDynamicOrigin)
				{
					center = m_PointerDownPos;
				}
				DrawGizmoCircle(center, m_MovementRange);
				if (m_Behaviour == Behaviour.ExactPositionWithDynamicOrigin)
				{
					Gizmos.color = new Color32(158, 84, 219, byte.MaxValue);
					DrawGizmoCircle(vector, m_DynamicOriginRange);
				}
			}
		}

		private void DrawGizmoCircle(Vector2 center, float radius)
		{
			for (int i = 0; i < 32; i++)
			{
				float f = (float)i / 32f * MathF.PI * 2f;
				float f2 = (float)(i + 1) / 32f * MathF.PI * 2f;
				Gizmos.DrawLine(new Vector3(center.x + Mathf.Cos(f) * radius, center.y + Mathf.Sin(f) * radius, 0f), new Vector3(center.x + Mathf.Cos(f2) * radius, center.y + Mathf.Sin(f2) * radius, 0f));
			}
		}

		private void UpdateDynamicOriginClickableArea()
		{
			Transform transform = base.transform.Find("DynamicOriginClickable");
			if ((bool)transform)
			{
				((RectTransform)transform).sizeDelta = new Vector2(m_DynamicOriginRange * 2f, m_DynamicOriginRange * 2f);
			}
		}
	}
}
namespace UnityEngine.InputSystem.HID
{
	public class HID : InputDevice
	{
		[Serializable]
		private class HIDLayoutBuilder
		{
			public string displayName;

			public HIDDeviceDescriptor hidDescriptor;

			public string parentLayout;

			public Type deviceType;

			public InputControlLayout Build()
			{
				InputControlLayout.Builder builder = new InputControlLayout.Builder
				{
					displayName = displayName,
					type = deviceType,
					extendsLayout = parentLayout,
					stateFormat = new FourCC('H', 'I', 'D')
				};
				HIDElementDescriptor hIDElementDescriptor = Array.Find(hidDescriptor.elements, (HIDElementDescriptor element) => element.usagePage == UsagePage.GenericDesktop && element.usage == 48);
				HIDElementDescriptor hIDElementDescriptor2 = Array.Find(hidDescriptor.elements, (HIDElementDescriptor element) => element.usagePage == UsagePage.GenericDesktop && element.usage == 49);
				bool flag = hIDElementDescriptor.usage == 48 && hIDElementDescriptor2.usage == 49;
				if (flag)
				{
					int bit;
					int num;
					int sizeInBits;
					if (hIDElementDescriptor.reportOffsetInBits <= hIDElementDescriptor2.reportOffsetInBits)
					{
						bit = hIDElementDescriptor.reportOffsetInBits % 8;
						num = hIDElementDescriptor.reportOffsetInBits / 8;
						sizeInBits = hIDElementDescriptor2.reportOffsetInBits + hIDElementDescriptor2.reportSizeInBits - hIDElementDescriptor.reportOffsetInBits;
					}
					else
					{
						bit = hIDElementDescriptor2.reportOffsetInBits % 8;
						num = hIDElementDescriptor2.reportOffsetInBits / 8;
						sizeInBits = hIDElementDescriptor.reportOffsetInBits + hIDElementDescriptor.reportSizeInBits - hIDElementDescriptor2.reportSizeInBits;
					}
					builder.AddControl("stick").WithDisplayName("Stick").WithLayout("Stick")
						.WithBitOffset((uint)bit)
						.WithByteOffset((uint)num)
						.WithSizeInBits((uint)sizeInBits)
						.WithUsages(CommonUsages.Primary2DMotion);
					string text = hIDElementDescriptor.DetermineParameters();
					string text2 = hIDElementDescriptor2.DetermineParameters();
					builder.AddControl("stick/x").WithFormat(hIDElementDescriptor.isSigned ? InputStateBlock.FormatSBit : InputStateBlock.FormatBit).WithByteOffset((uint)(hIDElementDescriptor.reportOffsetInBits / 8 - num))
						.WithBitOffset((uint)(hIDElementDescriptor.reportOffsetInBits % 8))
						.WithSizeInBits((uint)hIDElementDescriptor.reportSizeInBits)
						.WithParameters(text)
						.WithDefaultState(hIDElementDescriptor.DetermineDefaultState())
						.WithProcessors(hIDElementDescriptor.DetermineProcessors());
					builder.AddControl("stick/y").WithFormat(hIDElementDescriptor2.isSigned ? InputStateBlock.FormatSBit : InputStateBlock.FormatBit).WithByteOffset((uint)(hIDElementDescriptor2.reportOffsetInBits / 8 - num))
						.WithBitOffset((uint)(hIDElementDescriptor2.reportOffsetInBits % 8))
						.WithSizeInBits((uint)hIDElementDescriptor2.reportSizeInBits)
						.WithParameters(text2)
						.WithDefaultState(hIDElementDescriptor2.DetermineDefaultState())
						.WithProcessors(hIDElementDescriptor2.DetermineProcessors());
					builder.AddControl("stick/up").WithParameters(StringHelpers.Join<string>(",", text2, "clamp=2,clampMin=-1,clampMax=0,invert=true"));
					builder.AddControl("stick/down").WithParameters(StringHelpers.Join<string>(",", text2, "clamp=2,clampMin=0,clampMax=1,invert=false"));
					builder.AddControl("stick/left").WithParameters(StringHelpers.Join<string>(",", text, "clamp=2,clampMin=-1,clampMax=0,invert"));
					builder.AddControl("stick/right").WithParameters(StringHelpers.Join<string>(",", text, "clamp=2,clampMin=0,clampMax=1"));
				}
				HIDElementDescriptor[] elements = hidDescriptor.elements;
				int num2 = elements.Length;
				for (int num3 = 0; num3 < num2; num3++)
				{
					ref HIDElementDescriptor reference = ref elements[num3];
					if (reference.reportType != HIDReportType.Input || (flag && (reference.Is(UsagePage.GenericDesktop, 48) || reference.Is(UsagePage.GenericDesktop, 49))))
					{
						continue;
					}
					string text3 = reference.DetermineLayout();
					if (text3 != null)
					{
						string baseName = reference.DetermineName();
						baseName = StringHelpers.MakeUniqueName(baseName, builder.controls, (InputControlLayout.ControlItem x) => x.name);
						InputControlLayout.Builder.ControlBuilder controlBuilder = builder.AddControl(baseName).WithDisplayName(reference.DetermineDisplayName()).WithLayout(text3)
							.WithByteOffset((uint)reference.reportOffsetInBits / 8u)
							.WithBitOffset((uint)reference.reportOffsetInBits % 8u)
							.WithSizeInBits((uint)reference.reportSizeInBits)
							.WithFormat(reference.DetermineFormat())
							.WithDefaultState(reference.DetermineDefaultState())
							.WithProcessors(reference.DetermineProcessors());
						string text4 = reference.DetermineParameters();
						if (!string.IsNullOrEmpty(text4))
						{
							controlBuilder.WithParameters(text4);
						}
						InternedString[] array = reference.DetermineUsages();
						if (array != null)
						{
							controlBuilder.WithUsages(array);
						}
						reference.AddChildControls(ref reference, baseName, ref builder);
					}
				}
				return builder.Build();
			}
		}

		public enum HIDReportType
		{
			Unknown,
			Input,
			Output,
			Feature
		}

		public enum HIDCollectionType
		{
			Physical,
			Application,
			Logical,
			Report,
			NamedArray,
			UsageSwitch,
			UsageModifier
		}

		[Flags]
		public enum HIDElementFlags
		{
			Constant = 1,
			Variable = 2,
			Relative = 4,
			Wrap = 8,
			NonLinear = 0x10,
			NoPreferred = 0x20,
			NullState = 0x40,
			Volatile = 0x80,
			BufferedBytes = 0x100
		}

		[Serializable]
		public struct HIDElementDescriptor
		{
			public int usage;

			public UsagePage usagePage;

			public int unit;

			public int unitExponent;

			public int logicalMin;

			public int logicalMax;

			public int physicalMin;

			public int physicalMax;

			public HIDReportType reportType;

			public int collectionIndex;

			public int reportId;

			public int reportSizeInBits;

			public int reportOffsetInBits;

			public HIDElementFlags flags;

			public int? usageMin;

			public int? usageMax;

			public bool hasNullState => (flags & HIDElementFlags.NullState) == HIDElementFlags.NullState;

			public bool hasPreferredState => (flags & HIDElementFlags.NoPreferred) != HIDElementFlags.NoPreferred;

			public bool isArray => (flags & HIDElementFlags.Variable) != HIDElementFlags.Variable;

			public bool isNonLinear => (flags & HIDElementFlags.NonLinear) == HIDElementFlags.NonLinear;

			public bool isRelative => (flags & HIDElementFlags.Relative) == HIDElementFlags.Relative;

			public bool isConstant => (flags & HIDElementFlags.Constant) == HIDElementFlags.Constant;

			public bool isWrapping => (flags & HIDElementFlags.Wrap) == HIDElementFlags.Wrap;

			internal bool isSigned => logicalMin < 0;

			internal float minFloatValue
			{
				get
				{
					if (isSigned)
					{
						int minValue = (int)(-(1L << reportSizeInBits - 1));
						int maxValue = (int)((1L << reportSizeInBits - 1) - 1);
						return NumberHelpers.IntToNormalizedFloat(logicalMin, minValue, maxValue) * 2f - 1f;
					}
					uint maxValue2 = (uint)((1L << reportSizeInBits) - 1);
					return NumberHelpers.UIntToNormalizedFloat((uint)logicalMin, 0u, maxValue2);
				}
			}

			internal float maxFloatValue
			{
				get
				{
					if (isSigned)
					{
						int minValue = (int)(-(1L << reportSizeInBits - 1));
						int maxValue = (int)((1L << reportSizeInBits - 1) - 1);
						return NumberHelpers.IntToNormalizedFloat(logicalMax, minValue, maxValue) * 2f - 1f;
					}
					uint maxValue2 = (uint)((1L << reportSizeInBits) - 1);
					return NumberHelpers.UIntToNormalizedFloat((uint)logicalMax, 0u, maxValue2);
				}
			}

			public bool Is(UsagePage usagePage, int usage)
			{
				if (usagePage == this.usagePage)
				{
					return usage == this.usage;
				}
				return false;
			}

			internal string DetermineName()
			{
				switch (usagePage)
				{
				case UsagePage.Button:
					if (usage == 1)
					{
						return "trigger";
					}
					return $"button{usage}";
				case UsagePage.GenericDesktop:
				{
					if (usage == 57)
					{
						return "hat";
					}
					GenericDesktop genericDesktop = (GenericDesktop)usage;
					string text = genericDesktop.ToString();
					return char.ToLowerInvariant(text[0]) + text.Substring(1);
				}
				default:
					return $"UsagePage({usagePage:X}) Usage({usage:X})";
				}
			}

			internal string DetermineDisplayName()
			{
				switch (usagePage)
				{
				case UsagePage.Button:
					if (usage == 1)
					{
						return "Trigger";
					}
					return $"Button {usage}";
				case UsagePage.GenericDesktop:
				{
					GenericDesktop genericDesktop = (GenericDesktop)usage;
					return genericDesktop.ToString();
				}
				default:
					return null;
				}
			}

			internal bool IsUsableElement()
			{
				int num = usage;
				if ((uint)(num - 48) <= 1u)
				{
					return usagePage == UsagePage.GenericDesktop;
				}
				return DetermineLayout() != null;
			}

			internal string DetermineLayout()
			{
				if (reportType != HIDReportType.Input)
				{
					return null;
				}
				switch (usagePage)
				{
				case UsagePage.Button:
					return "Button";
				case UsagePage.GenericDesktop:
					switch (usage)
					{
					case 48:
					case 49:
					case 50:
					case 51:
					case 52:
					case 53:
					case 54:
					case 55:
					case 56:
					case 64:
					case 65:
					case 66:
					case 67:
					case 68:
					case 69:
						return "Axis";
					case 61:
					case 62:
					case 144:
					case 145:
					case 146:
					case 147:
						return "Button";
					case 57:
						if (logicalMax - logicalMin + 1 == 8)
						{
							return "Dpad";
						}
						break;
					}
					break;
				}
				return null;
			}

			internal FourCC DetermineFormat()
			{
				switch (reportSizeInBits)
				{
				case 8:
					if (!isSigned)
					{
						return InputStateBlock.FormatByte;
					}
					return InputStateBlock.FormatSByte;
				case 16:
					if (!isSigned)
					{
						return InputStateBlock.FormatUShort;
					}
					return InputStateBlock.FormatShort;
				case 32:
					if (!isSigned)
					{
						return InputStateBlock.FormatUInt;
					}
					return InputStateBlock.FormatInt;
				default:
					return InputStateBlock.FormatBit;
				}
			}

			internal InternedString[] DetermineUsages()
			{
				if (usagePage == UsagePage.Button && usage == 1)
				{
					return new InternedString[2]
					{
						CommonUsages.PrimaryTrigger,
						CommonUsages.PrimaryAction
					};
				}
				if (usagePage == UsagePage.Button && usage == 2)
				{
					return new InternedString[2]
					{
						CommonUsages.SecondaryTrigger,
						CommonUsages.SecondaryAction
					};
				}
				if (usagePage == UsagePage.GenericDesktop && usage == 53)
				{
					return new InternedString[1] { CommonUsages.Twist };
				}
				return null;
			}

			internal string DetermineParameters()
			{
				if (usagePage == UsagePage.GenericDesktop)
				{
					switch (usage)
					{
					case 48:
					case 50:
					case 51:
					case 53:
					case 54:
					case 55:
					case 56:
					case 64:
					case 66:
					case 67:
					case 69:
						return DetermineAxisNormalizationParameters();
					case 49:
					case 52:
					case 65:
					case 68:
						return StringHelpers.Join<string>(",", "invert", DetermineAxisNormalizationParameters());
					}
				}
				return null;
			}

			private string DetermineAxisNormalizationParameters()
			{
				if (logicalMin == 0 && logicalMax == 0)
				{
					return "normalize,normalizeMin=0,normalizeMax=1,normalizeZero=0.5";
				}
				float num = minFloatValue;
				float num2 = maxFloatValue;
				if (Mathf.Approximately(0f, num) && Mathf.Approximately(0f, num2))
				{
					return null;
				}
				float num3 = num + (num2 - num) / 2f;
				return string.Format(CultureInfo.InvariantCulture, "normalize,normalizeMin={0},normalizeMax={1},normalizeZero={2}", num, num2, num3);
			}

			internal string DetermineProcessors()
			{
				if (usagePage == UsagePage.GenericDesktop)
				{
					int num = usage;
					if ((uint)(num - 48) <= 8u || (uint)(num - 64) <= 5u)
					{
						return "axisDeadzone";
					}
				}
				return null;
			}

			internal PrimitiveValue DetermineDefaultState()
			{
				if (usagePage == UsagePage.GenericDesktop)
				{
					switch (usage)
					{
					case 57:
						if (hasNullState)
						{
							if (logicalMin >= 1)
							{
								return new PrimitiveValue(logicalMin - 1);
							}
							ulong num2 = (ulong)((1L << reportSizeInBits) - 1);
							if ((ulong)logicalMax < num2)
							{
								return new PrimitiveValue(logicalMax + 1);
							}
						}
						break;
					case 48:
					case 49:
					case 50:
					case 51:
					case 52:
					case 53:
					case 54:
					case 55:
					case 56:
					case 64:
					case 65:
					case 66:
					case 67:
					case 68:
					case 69:
						if (!isSigned)
						{
							int num = logicalMin + (logicalMax - logicalMin) / 2;
							if (num != 0)
							{
								return new PrimitiveValue(num);
							}
						}
						break;
					}
				}
				return default(PrimitiveValue);
			}

			internal void AddChildControls(ref HIDElementDescriptor element, string controlName, ref InputControlLayout.Builder builder)
			{
				if (usagePage == UsagePage.GenericDesktop && usage == 57)
				{
					PrimitiveValue primitiveValue = DetermineDefaultState();
					if (!primitiveValue.isEmpty)
					{
						builder.AddControl(controlName + "/up").WithFormat(InputStateBlock.FormatBit).WithLayout("DiscreteButton")
							.WithParameters(string.Format(CultureInfo.InvariantCulture, "minValue={0},maxValue={1},nullValue={2},wrapAtValue={3}", logicalMax, logicalMin + 1, primitiveValue.ToString(), logicalMax))
							.WithBitOffset((uint)element.reportOffsetInBits % 8u)
							.WithSizeInBits((uint)reportSizeInBits);
						builder.AddControl(controlName + "/right").WithFormat(InputStateBlock.FormatBit).WithLayout("DiscreteButton")
							.WithParameters(string.Format(CultureInfo.InvariantCulture, "minValue={0},maxValue={1}", logicalMin + 1, logicalMin + 3))
							.WithBitOffset((uint)element.reportOffsetInBits % 8u)
							.WithSizeInBits((uint)reportSizeInBits);
						builder.AddControl(controlName + "/down").WithFormat(InputStateBlock.FormatBit).WithLayout("DiscreteButton")
							.WithParameters(string.Format(CultureInfo.InvariantCulture, "minValue={0},maxValue={1}", logicalMin + 3, logicalMin + 5))
							.WithBitOffset((uint)element.reportOffsetInBits % 8u)
							.WithSizeInBits((uint)reportSizeInBits);
						builder.AddControl(controlName + "/left").WithFormat(InputStateBlock.FormatBit).WithLayout("DiscreteButton")
							.WithParameters(string.Format(CultureInfo.InvariantCulture, "minValue={0},maxValue={1}", logicalMin + 5, logicalMin + 7))
							.WithBitOffset((uint)element.reportOffsetInBits % 8u)
							.WithSizeInBits((uint)reportSizeInBits);
					}
				}
			}
		}

		[Serializable]
		public struct HIDCollectionDescriptor
		{
			public HIDCollectionType type;

			public int usage;

			public UsagePage usagePage;

			public int parent;

			public int childCount;

			public int firstChild;
		}

		[Serializable]
		public struct HIDDeviceDescriptor
		{
			public int vendorId;

			public int productId;

			public int usage;

			public UsagePage usagePage;

			public int inputReportSize;

			public int outputReportSize;

			public int featureReportSize;

			public HIDElementDescriptor[] elements;

			public HIDCollectionDescriptor[] collections;

			public string ToJson()
			{
				return JsonUtility.ToJson(this, prettyPrint: true);
			}

			public static HIDDeviceDescriptor FromJson(string json)
			{
				try
				{
					HIDDeviceDescriptor result = default(HIDDeviceDescriptor);
					ReadOnlySpan<char> readOnlySpan = MemoryExtensions.AsSpan(json);
					PredictiveParser predictiveParser = default(PredictiveParser);
					predictiveParser.ExpectSingleChar(readOnlySpan, '{');
					predictiveParser.AcceptString(readOnlySpan, out var output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.vendorId = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.productId = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.usage = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.usagePage = (UsagePage)predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.inputReportSize = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.outputReportSize = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out output);
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					result.featureReportSize = predictiveParser.ExpectInt(readOnlySpan);
					predictiveParser.AcceptSingleChar(readOnlySpan, ',');
					predictiveParser.AcceptString(readOnlySpan, out var output2);
					if (output2.ToString() != "elements")
					{
						return result;
					}
					predictiveParser.ExpectSingleChar(readOnlySpan, ':');
					predictiveParser.ExpectSingleChar(readOnlySpan, '[');
					List<HIDElementDescriptor> value;
					using (CollectionPool<List<HIDElementDescriptor>, HIDElementDescriptor>.Get(out value))
					{
						while (!predictiveParser.AcceptSingleChar(readOnlySpan, ']'))
						{
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectSingleChar(readOnlySpan, '{');
							HIDElementDescriptor item = default(HIDElementDescriptor);
							predictiveParser.AcceptSingleChar(readOnlySpan, '}');
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.usage = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.usagePage = (UsagePage)predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.unit = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.unitExponent = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.logicalMin = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.logicalMax = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.physicalMin = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.physicalMax = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.collectionIndex = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.reportType = (HIDReportType)predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.reportId = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							predictiveParser.AcceptInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.reportSizeInBits = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.reportOffsetInBits = predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.AcceptSingleChar(readOnlySpan, ',');
							predictiveParser.ExpectString(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, ':');
							item.flags = (HIDElementFlags)predictiveParser.ExpectInt(readOnlySpan);
							predictiveParser.ExpectSingleChar(readOnlySpan, '}');
							value.Add(item);
						}
						result.elements = value.ToArray();
						return result;
					}
				}
				catch (Exception)
				{
					return JsonUtility.FromJson<HIDDeviceDescriptor>(json);
				}
			}
		}

		public struct HIDDeviceDescriptorBuilder
		{
			public UsagePage usagePage;

			public int usage;

			private int m_CurrentReportId;

			private HIDReportType m_CurrentReportType;

			private int m_CurrentReportOffsetInBits;

			private List<HIDElementDescriptor> m_Elements;

			private List<HIDCollectionDescriptor> m_Collections;

			private int m_InputReportSize;

			private int m_OutputReportSize;

			private int m_FeatureReportSize;

			public HIDDeviceDescriptorBuilder(UsagePage usagePage, int usage)
			{
				this = default(HIDDeviceDescriptorBuilder);
				this.usagePage = usagePage;
				this.usage = usage;
			}

			public HIDDeviceDescriptorBuilder(GenericDesktop usage)
				: this(UsagePage.GenericDesktop, (int)usage)
			{
			}

			public HIDDeviceDescriptorBuilder StartReport(HIDReportType reportType, int reportId = 1)
			{
				m_CurrentReportId = reportId;
				m_CurrentReportType = reportType;
				m_CurrentReportOffsetInBits = 8;
				return this;
			}

			public HIDDeviceDescriptorBuilder AddElement(UsagePage usagePage, int usage, int sizeInBits)
			{
				if (m_Elements == null)
				{
					m_Elements = new List<HIDElementDescriptor>();
				}
				else
				{
					foreach (HIDElementDescriptor element in m_Elements)
					{
						if (element.reportId == m_CurrentReportId && element.reportType == m_CurrentReportType && element.usagePage == usagePage && element.usage == usage)
						{
							throw new InvalidOperationException($"Cannot add two elements with the same usage page '{usagePage}' and usage '0x{usage:X} the to same device");
						}
					}
				}
				m_Elements.Add(new HIDElementDescriptor
				{
					usage = usage,
					usagePage = usagePage,
					reportOffsetInBits = m_CurrentReportOffsetInBits,
					reportSizeInBits = sizeInBits,
					reportType = m_CurrentReportType,
					reportId = m_CurrentReportId
				});
				m_CurrentReportOffsetInBits += sizeInBits;
				return this;
			}

			public HIDDeviceDescriptorBuilder AddElement(GenericDesktop usage, int sizeInBits)
			{
				return AddElement(UsagePage.GenericDesktop, (int)usage, sizeInBits);
			}

			public HIDDeviceDescriptorBuilder WithPhysicalMinMax(int min, int max)
			{
				int num = m_Elements.Count - 1;
				if (num < 0)
				{
					throw new InvalidOperationException("No element has been added to the descriptor yet");
				}
				HIDElementDescriptor value = m_Elements[num];
				value.physicalMin = min;
				value.physicalMax = max;
				m_Elements[num] = value;
				return this;
			}

			public HIDDeviceDescriptorBuilder WithLogicalMinMax(int min, int max)
			{
				int num = m_Elements.Count - 1;
				if (num < 0)
				{
					throw new InvalidOperationException("No element has been added to the descriptor yet");
				}
				HIDElementDescriptor value = m_Elements[num];
				value.logicalMin = min;
				value.logicalMax = max;
				m_Elements[num] = value;
				return this;
			}

			public HIDDeviceDescriptor Finish()
			{
				return new HIDDeviceDescriptor
				{
					usage = usage,
					usagePage = usagePage,
					elements = m_Elements?.ToArray(),
					collections = m_Collections?.ToArray()
				};
			}
		}

