	internal static class InputUpdate
	{
		[Serializable]
		public struct UpdateStepCount
		{
			private bool m_WasUpdated;

			public uint value { get; private set; }

			public void OnBeforeUpdate()
			{
				m_WasUpdated = true;
				value++;
			}

			public void OnUpdate()
			{
				if (!m_WasUpdated)
				{
					value++;
				}
				m_WasUpdated = false;
			}
		}

		[Serializable]
		public struct SerializedState
		{
			public InputUpdateType lastUpdateType;

			public UpdateStepCount playerUpdateStepCount;
		}

		public static uint s_UpdateStepCount;

		public static InputUpdateType s_LatestUpdateType;

		public static UpdateStepCount s_PlayerUpdateStepCount;

		internal static void OnBeforeUpdate(InputUpdateType type)
		{
			s_LatestUpdateType = type;
			if ((uint)(type - 1) <= 1u || type == InputUpdateType.Manual)
			{
				s_PlayerUpdateStepCount.OnBeforeUpdate();
				s_UpdateStepCount = s_PlayerUpdateStepCount.value;
			}
		}

		internal static void OnUpdate(InputUpdateType type)
		{
			s_LatestUpdateType = type;
			if ((uint)(type - 1) <= 1u || type == InputUpdateType.Manual)
			{
				s_PlayerUpdateStepCount.OnUpdate();
				s_UpdateStepCount = s_PlayerUpdateStepCount.value;
			}
		}

		public static SerializedState Save()
		{
			return new SerializedState
			{
				lastUpdateType = s_LatestUpdateType,
				playerUpdateStepCount = s_PlayerUpdateStepCount
			};
		}

		public static void Restore(SerializedState state)
		{
			s_LatestUpdateType = state.lastUpdateType;
			s_PlayerUpdateStepCount = state.playerUpdateStepCount;
			InputUpdateType inputUpdateType = s_LatestUpdateType;
			if ((uint)(inputUpdateType - 1) <= 1u || inputUpdateType == InputUpdateType.Manual)
			{
				s_UpdateStepCount = s_PlayerUpdateStepCount.value;
			}
			else
			{
				s_UpdateStepCount = 0u;
			}
		}

		public static InputUpdateType GetUpdateTypeForPlayer(this InputUpdateType mask)
		{
			if ((mask & InputUpdateType.Manual) != InputUpdateType.None)
			{
				return InputUpdateType.Manual;
			}
			if ((mask & InputUpdateType.Dynamic) != InputUpdateType.None)
			{
				return InputUpdateType.Dynamic;
			}
			if ((mask & InputUpdateType.Fixed) != InputUpdateType.None)
			{
				return InputUpdateType.Fixed;
			}
			return InputUpdateType.None;
		}

		public static bool IsPlayerUpdate(this InputUpdateType updateType)
		{
			if (updateType == InputUpdateType.Editor)
			{
				return false;
			}
			return updateType != InputUpdateType.None;
		}
	}
	internal class NativeInputRuntime : IInputRuntime
	{
		public static readonly NativeInputRuntime instance = new NativeInputRuntime();

		private bool m_RunInBackground;

		private Action m_ShutdownMethod;

		private InputUpdateDelegate m_OnUpdate;

		private Action<InputUpdateType> m_OnBeforeUpdate;

		private Func<InputUpdateType, bool> m_OnShouldRunUpdate;

		private float m_PollingFrequency = 60f;

		private bool m_DidCallOnShutdown;

		private Action<bool> m_FocusChangedMethod;

		public unsafe InputUpdateDelegate onUpdate
		{
			get
			{
				return m_OnUpdate;
			}
			set
			{
				if (value != null)
				{
					NativeInputSystem.onUpdate = delegate(NativeInputUpdateType updateType, NativeInputEventBuffer* eventBufferPtr)
					{
						InputEventBuffer eventBuffer = new InputEventBuffer((InputEvent*)eventBufferPtr->eventBuffer, eventBufferPtr->eventCount, eventBufferPtr->sizeInBytes, eventBufferPtr->capacityInBytes);
						try
						{
							value((InputUpdateType)updateType, ref eventBuffer);
						}
						catch (Exception ex)
						{
							Debug.LogException(ex);
							Debug.LogError($"{ex.GetType().Name} during event processing of {updateType} update; resetting event buffer");
							eventBuffer.Reset();
						}
						if (eventBuffer.eventCount > 0)
						{
							eventBufferPtr->eventCount = eventBuffer.eventCount;
							eventBufferPtr->sizeInBytes = (int)eventBuffer.sizeInBytes;
							eventBufferPtr->capacityInBytes = (int)eventBuffer.capacityInBytes;
							eventBufferPtr->eventBuffer = NativeArrayUnsafeUtility.GetUnsafeBufferPointerWithoutChecks(eventBuffer.data);
						}
						else
						{
							eventBufferPtr->eventCount = 0;
							eventBufferPtr->sizeInBytes = 0;
						}
					};
				}
				else
				{
					NativeInputSystem.onUpdate = null;
				}
				m_OnUpdate = value;
			}
		}

		public Action<InputUpdateType> onBeforeUpdate
		{
			get
			{
				return m_OnBeforeUpdate;
			}
			set
			{
				if (value != null)
				{
					NativeInputSystem.onBeforeUpdate = delegate(NativeInputUpdateType updateType)
					{
						value((InputUpdateType)updateType);
					};
				}
				else
				{
					NativeInputSystem.onBeforeUpdate = null;
				}
				m_OnBeforeUpdate = value;
			}
		}

		public Func<InputUpdateType, bool> onShouldRunUpdate
		{
			get
			{
				return m_OnShouldRunUpdate;
			}
			set
			{
				if (value != null)
				{
					NativeInputSystem.onShouldRunUpdate = (NativeInputUpdateType updateType) => value((InputUpdateType)updateType);
				}
				else
				{
					NativeInputSystem.onShouldRunUpdate = null;
				}
				m_OnShouldRunUpdate = value;
			}
