			get
			{
				return m_ShutdownMethod;
			}
			set
			{
				if (value == null)
				{
					Application.quitting -= OnShutdown;
				}
				else if (m_ShutdownMethod == null)
				{
					Application.quitting += OnShutdown;
				}
				m_ShutdownMethod = value;
			}
		}

		public Action<bool> onPlayerFocusChanged
