				int num = items.Length;
				ControlItemJson[] array = new ControlItemJson[num];
				for (int i = 0; i < num; i++)
				{
					ControlItem controlItem = items[i];
					array[i] = new ControlItemJson
					{
						name = controlItem.name,
						layout = controlItem.layout,
						variants = controlItem.variants,
