				break;
			case InputActionPhase.Started:
				if (context.time - m_TimePressed >= (double)durationOrDefault)
				{
					context.PerformedAndStayPerformed();
				}
				if (!context.ControlIsActuated())
				{
					context.Canceled();
				}
				break;
			case InputActionPhase.Performed:
				if (!context.ControlIsActuated(pressPointOrDefault))
				{
					context.Canceled();
				}
				break;
			}
		}

		public void Reset()
		{
			m_TimePressed = 0.0;
		}
	}
	public class MultiTapInteraction : IInputInteraction<float>, IInputInteraction
	{
		private enum TapPhase
		{
			None,
			WaitingForNextRelease,
			WaitingForNextPress
		}

		[Tooltip("The maximum time (in seconds) allowed to elapse between pressing and releasing a control for it to register as a tap.")]
		public float tapTime;

		[Tooltip("The maximum delay (in seconds) allowed between each tap. If this time is exceeded, the multi-tap is canceled.")]
		public float tapDelay;

		[Tooltip("How many taps need to be performed in succession. Two means double-tap, three means triple-tap, and so on.")]
		public int tapCount = 2;

		public float pressPoint;

		private TapPhase m_CurrentTapPhase;

		private int m_CurrentTapCount;

		private double m_CurrentTapStartTime;

		private double m_LastTapReleaseTime;

		private float tapTimeOrDefault
		{
			get
			{
				if (!((double)tapTime > 0.0))
				{
					return InputSystem.settings.defaultTapTime;
				}
				return tapTime;
			}
		}

		internal float tapDelayOrDefault
		{
			get
			{
				if (!((double)tapDelay > 0.0))
				{
					return InputSystem.settings.multiTapDelayTime;
				}
				return tapDelay;
			}
		}

		private float pressPointOrDefault
		{
			get
			{
				if (!(pressPoint > 0f))
				{
					return ButtonControl.s_GlobalDefaultButtonPressPoint;
				}
				return pressPoint;
			}
		}

		private float releasePointOrDefault => pressPointOrDefault * ButtonControl.s_GlobalDefaultButtonReleaseThreshold;

		public void Process(ref InputInteractionContext context)
		{
			if (context.timerHasExpired)
			{
				context.Canceled();
				return;
			}
			switch (m_CurrentTapPhase)
			{
			case TapPhase.None:
				if (context.ControlIsActuated(pressPointOrDefault))
				{
					m_CurrentTapPhase = TapPhase.WaitingForNextRelease;
					m_CurrentTapStartTime = context.time;
					context.Started();
					float num = tapTimeOrDefault;
					float num2 = tapDelayOrDefault;
					context.SetTimeout(num);
					context.SetTotalTimeoutCompletionTime(num * (float)tapCount + (float)(tapCount - 1) * num2);
				}
				break;
			case TapPhase.WaitingForNextRelease:
				if (context.ControlIsActuated(releasePointOrDefault))
				{
					break;
				}
				if (context.time - m_CurrentTapStartTime <= (double)tapTimeOrDefault)
				{
					m_CurrentTapCount++;
					if (m_CurrentTapCount >= tapCount)
					{
						context.Performed();
						break;
					}
					m_CurrentTapPhase = TapPhase.WaitingForNextPress;
					m_LastTapReleaseTime = context.time;
					context.SetTimeout(tapDelayOrDefault);
				}
				else
				{
					context.Canceled();
				}
				break;
			case TapPhase.WaitingForNextPress:
				if (context.ControlIsActuated(pressPointOrDefault))
				{
					if (context.time - m_LastTapReleaseTime <= (double)tapDelayOrDefault)
					{
						m_CurrentTapPhase = TapPhase.WaitingForNextRelease;
						m_CurrentTapStartTime = context.time;
						context.SetTimeout(tapTimeOrDefault);
					}
					else
					{
						context.Canceled();
					}
				}
				break;
			}
		}

		public void Reset()
		{
			m_CurrentTapPhase = TapPhase.None;
			m_CurrentTapCount = 0;
			m_CurrentTapStartTime = 0.0;
			m_LastTapReleaseTime = 0.0;
		}
	}
	[DisplayName("Press")]
	public class PressInteraction : IInputInteraction
	{
		[Tooltip("The amount of actuation a control requires before being considered pressed. If not set, default to 'Default Press Point' in the global input settings.")]
		public float pressPoint;

		[Tooltip("Determines how button presses trigger the action. By default (PressOnly), the action is performed on press. With ReleaseOnly, the action is performed on release. With PressAndRelease, the action is performed on press and release.")]
		public PressBehavior behavior;

		private bool m_WaitingForRelease;

		private float pressPointOrDefault
		{
			get
			{
				if (!(pressPoint > 0f))
				{
					return ButtonControl.s_GlobalDefaultButtonPressPoint;
				}
				return pressPoint;
			}
		}

		private float releasePointOrDefault => pressPointOrDefault * ButtonControl.s_GlobalDefaultButtonReleaseThreshold;

		public void Process(ref InputInteractionContext context)
		{
			float num = context.ComputeMagnitude();
			switch (behavior)
			{
			case PressBehavior.PressOnly:
				if (m_WaitingForRelease)
				{
					if (num <= releasePointOrDefault)
					{
						m_WaitingForRelease = false;
						if (Mathf.Approximately(0f, num))
						{
							context.Canceled();
						}
						else
						{
							context.Started();
						}
					}
				}
				else if (num >= pressPointOrDefault)
				{
					m_WaitingForRelease = true;
					context.PerformedAndStayPerformed();
				}
				else if (num > 0f && !context.isStarted)
				{
					context.Started();
				}
				else if (Mathf.Approximately(0f, num) && context.isStarted)
				{
					context.Canceled();
				}
				break;
			case PressBehavior.ReleaseOnly:
			{
				if (m_WaitingForRelease)
				{
					if (num <= releasePointOrDefault)
					{
						m_WaitingForRelease = false;
						context.Performed();
						context.Canceled();
					}
					break;
				}
				if (num >= pressPointOrDefault)
				{
					m_WaitingForRelease = true;
					if (!context.isStarted)
					{
						context.Started();
					}
					break;
				}
				bool isStarted2 = context.isStarted;
				if (num > 0f && !isStarted2)
				{
					context.Started();
				}
				else if (Mathf.Approximately(0f, num) && isStarted2)
				{
					context.Canceled();
				}
				break;
			}
			case PressBehavior.PressAndRelease:
				if (m_WaitingForRelease)
				{
					if (num <= releasePointOrDefault)
					{
						m_WaitingForRelease = false;
						context.Performed();
						if (Mathf.Approximately(0f, num))
						{
							context.Canceled();
						}
					}
				}
				else if (num >= pressPointOrDefault)
				{
					m_WaitingForRelease = true;
					context.PerformedAndStayPerformed();
				}
				else
				{
					bool isStarted = context.isStarted;
					if (num > 0f && !isStarted)
					{
						context.Started();
					}
					else if (Mathf.Approximately(0f, num) && isStarted)
					{
						context.Canceled();
					}
				}
				break;
			}
		}

		public void Reset()
		{
			m_WaitingForRelease = false;
		}
	}
