			}
			NativeArray<TValue> nativeArray = new NativeArray<TValue>(length + count, allocator);
			UnsafeUtility.MemCpy(nativeArray.GetUnsafePtr(), array.GetUnsafeReadOnlyPtr(), (long)length * (long)UnsafeUtility.SizeOf<TValue>());
			array.Dispose();
			array = nativeArray;
			return length;
		}

