			{
				return type switch
				{
					JsonValueType.Bool => boolValue ? 1 : 0, 
					JsonValueType.Integer => integerValue, 
					JsonValueType.Real => (long)realValue, 
					JsonValueType.String => Convert.ToInt64(ToString()), 
					_ => 0L, 
				};
