				*num3 |= (byte)(((byte*)source)[num] & ((byte*)mask)[num]);
				numBytes--;
				num++;
			}
		}

		public unsafe static uint ReadMultipleBitsAsUInt(void* ptr, uint bitOffset, uint bitCount)
		{
			if (ptr == null)
			{
				throw new ArgumentNullException("ptr");
			}
			if (bitCount > 32)
			{
				throw new ArgumentException("Trying to read more than 32 bits as int", "bitCount");
			}
			if (bitOffset > 32)
			{
				int num = (int)bitOffset % 32;
				int num2 = ((int)bitOffset - num) / 32;
				ptr = (byte*)ptr + num2 * 4;
				bitOffset = (uint)num;
			}
			if (bitOffset + bitCount <= 8)
			{
				byte num3 = (byte)(*(byte*)ptr >> (int)bitOffset);
				uint num4 = 255u >> (int)(8 - bitCount);
				return num3 & num4;
			}
			if (bitOffset + bitCount <= 16)
			{
				ushort num5 = (ushort)(*(ushort*)ptr >> (int)bitOffset);
				uint num6 = 65535u >> (int)(16 - bitCount);
				return num5 & num6;
			}
			if (bitOffset + bitCount <= 32)
			{
				uint num7 = *(uint*)ptr >> (int)bitOffset;
				uint num8 = uint.MaxValue >> (int)(32 - bitCount);
				return num7 & num8;
			}
			throw new NotImplementedException("Reading int straddling int boundary");
		}

		public unsafe static void WriteUIntAsMultipleBits(void* ptr, uint bitOffset, uint bitCount, uint value)
		{
			if (ptr == null)
			{
				throw new ArgumentNullException("ptr");
			}
			if (bitCount > 32)
			{
				throw new ArgumentException("Trying to write more than 32 bits as int", "bitCount");
			}
			if (bitOffset > 32)
			{
				int num = (int)bitOffset % 32;
				int num2 = ((int)bitOffset - num) / 32;
				ptr = (byte*)ptr + num2 * 4;
				bitOffset = (uint)num;
			}
			if (bitOffset + bitCount <= 8)
			{
				byte b = (byte)value;
				b = (byte)(b << (int)bitOffset);
				uint num3 = (uint)(~(255 >>> (int)(8 - bitCount) << (int)bitOffset));
				*(byte*)ptr = (byte)((*(byte*)ptr & num3) | b);
				return;
			}
			if (bitOffset + bitCount <= 16)
			{
				ushort num4 = (ushort)value;
				num4 = (ushort)(num4 << (int)bitOffset);
				uint num5 = (uint)(~(65535 >>> (int)(16 - bitCount) << (int)bitOffset));
				*(ushort*)ptr = (ushort)((*(ushort*)ptr & num5) | num4);
				return;
			}
			if (bitOffset + bitCount <= 32)
			{
				uint num6 = value;
				num6 <<= (int)bitOffset;
				uint num7 = (uint)(~(-1 >>> (int)(32 - bitCount) << (int)bitOffset));
				*(uint*)ptr = (*(uint*)ptr & num7) | num6;
				return;
			}
			throw new NotImplementedException("Writing int straddling int boundary");
		}

		public unsafe static int ReadTwosComplementMultipleBitsAsInt(void* ptr, uint bitOffset, uint bitCount)
		{
			return (int)ReadMultipleBitsAsUInt(ptr, bitOffset, bitCount);
		}

		public unsafe static void WriteIntAsTwosComplementMultipleBits(void* ptr, uint bitOffset, uint bitCount, int value)
		{
			WriteUIntAsMultipleBits(ptr, bitOffset, bitCount, (uint)value);
		}

		public unsafe static int ReadExcessKMultipleBitsAsInt(void* ptr, uint bitOffset, uint bitCount)
		{
			long num = ReadMultipleBitsAsUInt(ptr, bitOffset, bitCount);
			long num2 = (long)((ulong)(1L << (int)bitCount) / 2uL);
			return (int)(num - num2);
		}

		public unsafe static void WriteIntAsExcessKMultipleBits(void* ptr, uint bitOffset, uint bitCount, int value)
		{
			long num = (long)((ulong)(1L << (int)bitCount) / 2uL) + (long)value;
			WriteUIntAsMultipleBits(ptr, bitOffset, bitCount, (uint)num);
		}

		public unsafe static float ReadMultipleBitsAsNormalizedUInt(void* ptr, uint bitOffset, uint bitCount)
		{
			uint value = ReadMultipleBitsAsUInt(ptr, bitOffset, bitCount);
			uint maxValue = (uint)((1L << (int)bitCount) - 1);
			return NumberHelpers.UIntToNormalizedFloat(value, 0u, maxValue);
		}

		public unsafe static void WriteNormalizedUIntAsMultipleBits(void* ptr, uint bitOffset, uint bitCount, float value)
		{
			uint uintMaxValue = (uint)((1L << (int)bitCount) - 1);
			uint value2 = NumberHelpers.NormalizedFloatToUInt(value, 0u, uintMaxValue);
			WriteUIntAsMultipleBits(ptr, bitOffset, bitCount, value2);
		}

		public unsafe static void SetBitsInBuffer(void* buffer, int byteOffset, int bitOffset, int sizeInBits, bool value)
		{
			if (buffer == null)
			{
				throw new ArgumentException("A buffer must be provided to apply the bitmask on", "buffer");
			}
			if (sizeInBits < 0)
			{
				throw new ArgumentException("Negative sizeInBits", "sizeInBits");
			}
			if (bitOffset < 0)
			{
				throw new ArgumentException("Negative bitOffset", "bitOffset");
			}
			if (byteOffset < 0)
			{
				throw new ArgumentException("Negative byteOffset", "byteOffset");
			}
			if (bitOffset >= 8)
			{
				int num = bitOffset / 8;
				byteOffset += num;
				bitOffset %= 8;
			}
			byte* ptr = (byte*)buffer + byteOffset;
			int num2 = sizeInBits;
			if (bitOffset != 0)
			{
				int num3 = 255 << bitOffset;
				if (num2 + bitOffset < 8)
				{
					num3 &= 255 >> 8 - (num2 + bitOffset);
				}
				if (value)
				{
					byte* intPtr = ptr;
					*intPtr |= (byte)num3;
				}
				else
				{
					byte* intPtr2 = ptr;
					*intPtr2 &= (byte)(~num3);
				}
				ptr++;
				num2 -= 8 - bitOffset;
			}
			while (num2 >= 8)
			{
				*ptr = (byte)(value ? byte.MaxValue : 0);
				ptr++;
				num2 -= 8;
			}
			if (num2 > 0)
			{
				byte b = (byte)(255 >> 8 - num2);
				if (value)
				{
					byte* intPtr3 = ptr;
					*intPtr3 |= b;
				}
				else
				{
					byte* intPtr4 = ptr;
					*intPtr4 &= (byte)(~b);
				}
			}
		}

		public static void Swap<TValue>(ref TValue a, ref TValue b)
		{
			TValue val = a;
			a = b;
			b = val;
		}

		public static uint AlignNatural(uint offset, uint sizeInBytes)
		{
			uint alignment = Math.Min(8u, sizeInBytes);
			return offset.AlignToMultipleOf(alignment);
		}
	}
	internal static class MiscHelpers
	{
		public static TValue GetValueOrDefault<TKey, TValue>(this Dictionary<TKey, TValue> dictionary, TKey key)
		{
			if (!dictionary.TryGetValue(key, out var value))
			{
				return default(TValue);
			}
			return value;
		}

		public static IEnumerable<TValue> EveryNth<TValue>(this IEnumerable<TValue> enumerable, int n, int start = 0)
		{
			int index = 0;
			foreach (TValue item in enumerable)
			{
				int num;
				if (index < start)
				{
					num = index + 1;
					index = num;
					continue;
				}
				if ((index - start) % n == 0)
				{
					yield return item;
				}
				num = index + 1;
				index = num;
			}
		}

		public static int IndexOf<TValue>(this IEnumerable<TValue> enumerable, TValue value)
		{
			int num = 0;
			foreach (TValue item in enumerable)
			{
				if (EqualityComparer<TValue>.Default.Equals(item, value))
				{
					return num;
				}
				num++;
			}
			return -1;
		}
	}
	public struct NameAndParameters
	{
		public string name { get; set; }

		public ReadOnlyArray<NamedValue> parameters { get; set; }

		public override string ToString()
		{
			if (parameters.Count == 0)
			{
				return name;
			}
			string text = string.Join(",", parameters.Select((NamedValue x) => x.ToString()).ToArray());
			return name + "(" + text + ")";
		}

		public static IEnumerable<NameAndParameters> ParseMultiple(string text)
		{
			List<NameAndParameters> list = null;
			if (!ParseMultiple(text, ref list))
			{
				return Enumerable.Empty<NameAndParameters>();
			}
			return list;
		}

		internal static bool ParseMultiple(string text, ref List<NameAndParameters> list)
		{
			text = text.Trim();
			if (string.IsNullOrEmpty(text))
			{
				return false;
			}
			if (list == null)
			{
				list = new List<NameAndParameters>();
			}
			else
			{
				list.Clear();
			}
			int index = 0;
			int length = text.Length;
			while (index < length)
			{
				list.Add(ParseNameAndParameters(text, ref index));
			}
			return true;
		}

		internal static string ParseName(string text)
		{
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			int index = 0;
			return ParseNameAndParameters(text, ref index, nameOnly: true).name;
		}

		public static NameAndParameters Parse(string text)
		{
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			int index = 0;
			return ParseNameAndParameters(text, ref index);
		}

		private static NameAndParameters ParseNameAndParameters(string text, ref int index, bool nameOnly = false)
		{
			int length = text.Length;
			while (index < length && char.IsWhiteSpace(text[index]))
			{
				index++;
			}
			int num = index;
			while (index < length)
			{
				char c = text[index];
				if (c == '(' || c == ","[0] || char.IsWhiteSpace(c))
				{
					break;
				}
				index++;
			}
			if (index - num == 0)
			{
				throw new ArgumentException($"Expecting name at position {num} in '{text}'", "text");
			}
			string text2 = text.Substring(num, index - num);
			if (nameOnly)
			{
				return new NameAndParameters
				{
					name = text2
				};
			}
			while (index < length && char.IsWhiteSpace(text[index]))
			{
				index++;
			}
			NamedValue[] array = null;
			if (index < length && text[index] == '(')
			{
				index++;
				int num2 = text.IndexOf(')', index);
				if (num2 == -1)
				{
					throw new ArgumentException($"Expecting ')' after '(' at position {index} in '{text}'", "text");
				}
				array = NamedValue.ParseMultiple(text.Substring(index, num2 - index));
				index = num2 + 1;
			}
			if (index < length && (text[index] == ',' || text[index] == ';'))
			{
				index++;
			}
			return new NameAndParameters
			{
				name = text2,
				parameters = new ReadOnlyArray<NamedValue>(array)
			};
		}
	}
	public struct NamedValue : IEquatable<NamedValue>
	{
		public const string Separator = ",";

		public string name { get; set; }

		public PrimitiveValue value { get; set; }

		public TypeCode type => value.type;

		public NamedValue ConvertTo(TypeCode type)
		{
			return new NamedValue
			{
				name = name,
				value = value.ConvertTo(type)
			};
		}

		public static NamedValue From<TValue>(string name, TValue value) where TValue : struct
		{
			return new NamedValue
			{
				name = name,
				value = PrimitiveValue.From(value)
			};
		}

		public override string ToString()
		{
			return $"{name}={value}";
		}

		public bool Equals(NamedValue other)
		{
			if (string.Equals(name, other.name, StringComparison.InvariantCultureIgnoreCase))
			{
				return value == other.value;
			}
			return false;
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			if (obj is NamedValue other)
			{
				return Equals(other);
			}
			return false;
		}

		public override int GetHashCode()
		{
			return (((name != null) ? name.GetHashCode() : 0) * 397) ^ value.GetHashCode();
		}

		public static bool operator ==(NamedValue left, NamedValue right)
		{
			return left.Equals(right);
		}

		public static bool operator !=(NamedValue left, NamedValue right)
		{
			return !left.Equals(right);
		}

		public static NamedValue[] ParseMultiple(string parameterString)
		{
			if (parameterString == null)
			{
				throw new ArgumentNullException("parameterString");
			}
			parameterString = parameterString.Trim();
			if (string.IsNullOrEmpty(parameterString))
			{
				return null;
			}
			int num = parameterString.CountOccurrences(","[0]) + 1;
			NamedValue[] array = new NamedValue[num];
			int index = 0;
			for (int i = 0; i < num; i++)
			{
				NamedValue namedValue = ParseParameter(parameterString, ref index);
				array[i] = namedValue;
			}
			return array;
		}

		public static NamedValue Parse(string str)
		{
			int index = 0;
			return ParseParameter(str, ref index);
		}

		private static NamedValue ParseParameter(string parameterString, ref int index)
		{
			NamedValue result = default(NamedValue);
			int length = parameterString.Length;
			while (index < length && char.IsWhiteSpace(parameterString[index]))
			{
				index++;
			}
			int num = index;
			while (index < length)
			{
				char c = parameterString[index];
				if (c == '=' || c == ","[0] || char.IsWhiteSpace(c))
				{
					break;
				}
				index++;
			}
			result.name = parameterString.Substring(num, index - num);
			while (index < length && char.IsWhiteSpace(parameterString[index]))
			{
				index++;
			}
			if (index == length || parameterString[index] != '=')
			{
				result.value = true;
			}
			else
			{
				index++;
				while (index < length && char.IsWhiteSpace(parameterString[index]))
				{
					index++;
				}
				int num2 = index;
				while (index < length && parameterString[index] != ","[0] && !char.IsWhiteSpace(parameterString[index]))
				{
					index++;
				}
				string text = parameterString.Substring(num2, index - num2);
				result.value = PrimitiveValue.FromString(text);
			}
			if (index < length && parameterString[index] == ","[0])
			{
				index++;
			}
			return result;
		}

		public void ApplyToObject(object instance)
		{
			if (instance == null)
			{
				throw new ArgumentNullException("instance");
			}
			Type type = instance.GetType();
			FieldInfo field = type.GetField(name, BindingFlags.IgnoreCase | BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
			if (field == null)
			{
				throw new ArgumentException("Cannot find public field '" + name + "' in '" + type.Name + "' (while trying to apply parameter)", "instance");
			}
			TypeCode typeCode = Type.GetTypeCode(field.FieldType);
			field.SetValue(instance, value.ConvertTo(typeCode).ToObject());
		}

		public static void ApplyAllToObject<TParameterList>(object instance, TParameterList parameters) where TParameterList : IEnumerable<NamedValue>
		{
			foreach (NamedValue item in parameters)
			{
				item.ApplyToObject(instance);
			}
		}
	}
	internal static class NumberHelpers
	{
		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static int AlignToMultipleOf(this int number, int alignment)
		{
			int num = number % alignment;
			if (num == 0)
			{
				return number;
			}
			return number + alignment - num;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static long AlignToMultipleOf(this long number, long alignment)
		{
			long num = number % alignment;
			if (num == 0L)
			{
				return number;
			}
			return number + alignment - num;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static uint AlignToMultipleOf(this uint number, uint alignment)
		{
			uint num = number % alignment;
			if (num == 0)
			{
				return number;
			}
			return number + alignment - num;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static bool Approximately(double a, double b)
		{
			return Math.Abs(b - a) < Math.Max(1E-06 * Math.Max(Math.Abs(a), Math.Abs(b)), 4E-323);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static float IntToNormalizedFloat(int value, int minValue, int maxValue)
		{
			if (value <= minValue)
			{
				return 0f;
			}
			if (value >= maxValue)
			{
				return 1f;
			}
			return (float)(((double)value - (double)minValue) / ((double)maxValue - (double)minValue));
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static int NormalizedFloatToInt(float value, int intMinValue, int intMaxValue)
		{
			if (value <= 0f)
			{
				return intMinValue;
			}
			if (value >= 1f)
			{
				return intMaxValue;
			}
			return (int)((double)value * ((double)intMaxValue - (double)intMinValue) + (double)intMinValue);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static float UIntToNormalizedFloat(uint value, uint minValue, uint maxValue)
		{
			if (value <= minValue)
			{
				return 0f;
			}
			if (value >= maxValue)
			{
				return 1f;
			}
			return (float)(((double)value - (double)minValue) / ((double)maxValue - (double)minValue));
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static uint NormalizedFloatToUInt(float value, uint uintMinValue, uint uintMaxValue)
		{
			if (value <= 0f)
			{
				return uintMinValue;
			}
			if (value >= 1f)
			{
				return uintMaxValue;
			}
			return (uint)((double)value * ((double)uintMaxValue - (double)uintMinValue) + (double)uintMinValue);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static uint RemapUIntBitsToNormalizeFloatToUIntBits(uint value, uint inBitSize, uint outBitSize)
		{
			uint maxValue = (uint)((1L << (int)inBitSize) - 1);
			uint uintMaxValue = (uint)((1L << (int)outBitSize) - 1);
			return NormalizedFloatToUInt(UIntToNormalizedFloat(value, 0u, maxValue), 0u, uintMaxValue);
		}
	}
	internal class ForDeviceEventObservable : IObservable<InputEventPtr>
	{
		private class ForDevice : IObserver<InputEventPtr>
		{
			private IObserver<InputEventPtr> m_Observer;

			private InputDevice m_Device;

			private Type m_DeviceType;

			public ForDevice(Type deviceType, InputDevice device, IObserver<InputEventPtr> observer)
			{
				m_Device = device;
				m_DeviceType = deviceType;
				m_Observer = observer;
			}

			public void OnCompleted()
			{
			}

			public void OnError(Exception error)
			{
				Debug.LogException(error);
			}

			public void OnNext(InputEventPtr value)
			{
				if (m_DeviceType != null)
				{
					InputDevice deviceById = InputSystem.GetDeviceById(value.deviceId);
					if (deviceById == null || !m_DeviceType.IsInstanceOfType(deviceById))
					{
						return;
					}
				}
				if (m_Device == null || value.deviceId == m_Device.deviceId)
				{
					m_Observer.OnNext(value);
				}
			}
		}

		private IObservable<InputEventPtr> m_Source;

		private InputDevice m_Device;

		private Type m_DeviceType;

		public ForDeviceEventObservable(IObservable<InputEventPtr> source, Type deviceType, InputDevice device)
		{
			m_Source = source;
			m_DeviceType = deviceType;
			m_Device = device;
		}

		public IDisposable Subscribe(IObserver<InputEventPtr> observer)
		{
			return m_Source.Subscribe(new ForDevice(m_DeviceType, m_Device, observer));
		}
	}
	public static class Observable
	{
