		}

		public static string GetPlural(this string str)
		{
			if (str == null)
			{
				throw new ArgumentNullException("str");
			}
			return str switch
			{
				"Mouse" => "Mice", 
				"mouse" => "mice", 
				"Axis" => "Axes", 
				"axis" => "axes", 
				_ => str + "s", 
			};
		}

		public static string NicifyMemorySize(long numBytes)
		{
			if (numBytes > 1073741824)
			{
				long num = numBytes / 1073741824;
				float num2 = (float)(numBytes % 1073741824) / 1f;
				return $"{(float)num + num2} GB";
			}
			if (numBytes > 1048576)
			{
				long num3 = numBytes / 1048576;
				float num4 = (float)(numBytes % 1048576) / 1f;
				return $"{(float)num3 + num4} MB";
			}
			if (numBytes > 1024)
			{
				long num5 = numBytes / 1024;
				float num6 = (float)(numBytes % 1024) / 1f;
				return $"{(float)num5 + num6} KB";
			}
			return $"{numBytes} Bytes";
		}

		public static bool FromNicifiedMemorySize(string text, out long result, long defaultMultiplier = 1L)
		{
			text = text.Trim();
			long num = defaultMultiplier;
			if (text.EndsWith("MB", StringComparison.InvariantCultureIgnoreCase))
			{
				num = 1048576L;
				text = text.Substring(0, text.Length - 2);
			}
			else if (text.EndsWith("GB", StringComparison.InvariantCultureIgnoreCase))
			{
				num = 1073741824L;
				text = text.Substring(0, text.Length - 2);
			}
			else if (text.EndsWith("KB", StringComparison.InvariantCultureIgnoreCase))
			{
				num = 1024L;
				text = text.Substring(0, text.Length - 2);
			}
			else if (text.EndsWith("Bytes", StringComparison.InvariantCultureIgnoreCase))
			{
				num = 1L;
				text = text.Substring(0, text.Length - "Bytes".Length);
			}
			if (!long.TryParse(text, out var result2))
			{
				result = 0L;
				return false;
			}
			result = result2 * num;
			return true;
		}

		public static int CountOccurrences(this string str, char ch)
		{
			if (str == null)
			{
				return 0;
			}
			int length = str.Length;
			int num = 0;
			int num2 = 0;
			while (num < length)
			{
				int num3 = str.IndexOf(ch, num);
				if (num3 == -1)
				{
					break;
				}
				num2++;
				num = num3 + 1;
			}
			return num2;
		}

		public static IEnumerable<Substring> Tokenize(this string str)
		{
			int i = 0;
			int length = str.Length;
			while (i < length)
			{
				for (; i < length && char.IsWhiteSpace(str[i]); i++)
				{
				}
				if (i == length)
				{
					break;
				}
				if (str[i] == '"')
				{
					i++;
					int endPos = i;
					while (endPos < length && str[endPos] != '"')
					{
						int num;
						if (str[endPos] == '\\' && endPos < length - 1)
						{
							num = endPos + 1;
							endPos = num;
						}
						num = endPos + 1;
						endPos = num;
					}
					yield return new Substring(str, i, endPos - i);
					i = endPos + 1;
				}
				else
				{
					int endPos = i;
					while (endPos < length && !char.IsWhiteSpace(str[endPos]))
					{
						int num = endPos + 1;
						endPos = num;
					}
					yield return new Substring(str, i, endPos - i);
					i = endPos;
				}
			}
		}

		public static IEnumerable<string> Split(this string str, Func<char, bool> predicate)
		{
			if (string.IsNullOrEmpty(str))
			{
				yield break;
			}
			int length = str.Length;
			int position = 0;
			while (position < length)
			{
				char arg = str[position];
				int num;
				if (predicate(arg))
				{
					num = position + 1;
					position = num;
					continue;
				}
				int num2 = position;
				num = position + 1;
				for (position = num; position < length; position = num)
				{
					arg = str[position];
					if (predicate(arg))
					{
						break;
					}
					num = position + 1;
				}
				yield return str.Substring(num2, position - num2);
			}
		}

		public static string Join<TValue>(string separator, params TValue[] values)
		{
			return Join(values, separator);
		}

		public static string Join<TValue>(IEnumerable<TValue> values, string separator)
		{
			string text = null;
			int num = 0;
			StringBuilder stringBuilder = null;
			foreach (TValue value in values)
			{
				if (value == null)
				{
					continue;
				}
				string text2 = value.ToString();
				if (!string.IsNullOrEmpty(text2))
				{
					num++;
					switch (num)
					{
					case 1:
						text = text2;
						continue;
					case 2:
						stringBuilder = new StringBuilder();
						stringBuilder.Append(text);
						break;
					}
					stringBuilder.Append(separator);
					stringBuilder.Append(text2);
				}
			}
			return num switch
			{
				0 => null, 
				1 => text, 
				_ => stringBuilder.ToString(), 
			};
		}

		public static string MakeUniqueName<TExisting>(string baseName, IEnumerable<TExisting> existingSet, Func<TExisting, string> getNameFunc)
		{
			if (getNameFunc == null)
			{
				throw new ArgumentNullException("getNameFunc");
			}
			if (existingSet == null)
			{
				return baseName;
			}
			string text = baseName;
			bool flag = false;
			int num = 1;
			if (baseName.Length > 0)
			{
				int num2 = baseName.Length;
				while (num2 > 0 && char.IsDigit(baseName[num2 - 1]))
				{
					num2--;
				}
				if (num2 != baseName.Length)
				{
					num = int.Parse(baseName.Substring(num2)) + 1;
					baseName = baseName.Substring(0, num2);
				}
			}
			while (!flag)
			{
				flag = true;
				foreach (TExisting item in existingSet)
				{
					if (getNameFunc(item).Equals(text, StringComparison.InvariantCultureIgnoreCase))
					{
						text = $"{baseName}{num}";
						flag = false;
						num++;
						break;
					}
				}
			}
			return text;
		}

		public static bool CharacterSeparatedListsHaveAtLeastOneCommonElement(string firstList, string secondList, char separator)
		{
			if (firstList == null)
			{
				throw new ArgumentNullException("firstList");
			}
			if (secondList == null)
			{
				throw new ArgumentNullException("secondList");
			}
			int num = 0;
			int length = firstList.Length;
			int length2 = secondList.Length;
			while (num < length)
			{
				if (firstList[num] == separator)
				{
					num++;
				}
				int i;
				for (i = num + 1; i < length && firstList[i] != separator; i++)
				{
				}
				int num2 = i - num;
				int num3 = 0;
				while (num3 < length2)
				{
					if (secondList[num3] == separator)
					{
						num3++;
					}
					int j;
					for (j = num3 + 1; j < length2 && secondList[j] != separator; j++)
					{
					}
					int num4 = j - num3;
					if (num2 == num4)
					{
						int num5 = num;
						int num6 = num3;
						bool flag = true;
						for (int k = 0; k < num2; k++)
						{
							char c = firstList[num5 + k];
							char c2 = secondList[num6 + k];
							if (char.ToLowerInvariant(c) != char.ToLowerInvariant(c2))
							{
								flag = false;
								break;
							}
						}
						if (flag)
						{
							return true;
						}
					}
					num3 = j + 1;
				}
				num = i + 1;
			}
			return false;
		}

		public static int ParseInt(string str, int pos)
		{
			int num = 1;
			int num2 = 0;
			int length = str.Length;
			while (pos < length)
			{
				int num3 = str[pos] - 48;
				if (num3 < 0 || num3 > 9)
				{
					break;
				}
				num2 = num2 * num + num3;
				num *= 10;
				pos++;
			}
			return num2;
		}

		public static bool WriteStringToBuffer(string text, IntPtr buffer, int bufferSizeInCharacters)
		{
			uint offset = 0u;
			return WriteStringToBuffer(text, buffer, bufferSizeInCharacters, ref offset);
		}

		public unsafe static bool WriteStringToBuffer(string text, IntPtr buffer, int bufferSizeInCharacters, ref uint offset)
		{
			if (buffer == IntPtr.Zero)
			{
				throw new ArgumentNullException("buffer");
			}
			int num = ((!string.IsNullOrEmpty(text)) ? text.Length : 0);
			if (num > 65535)
			{
				throw new ArgumentException($"String exceeds max size of {ushort.MaxValue} characters", "text");
			}
			long num2 = offset + 2 * num + 4;
			if (num2 > bufferSizeInCharacters)
			{
				return false;
			}
			byte* ptr = (byte*)(void*)buffer + offset;
			*(ushort*)ptr = (ushort)num;
			ptr += 2;
			int num3 = 0;
			while (num3 < num)
			{
				*(char*)ptr = text[num3];
				num3++;
				ptr += 2;
			}
			offset = (uint)num2;
			return true;
		}

		public static string ReadStringFromBuffer(IntPtr buffer, int bufferSize)
		{
			uint offset = 0u;
			return ReadStringFromBuffer(buffer, bufferSize, ref offset);
		}

		public unsafe static string ReadStringFromBuffer(IntPtr buffer, int bufferSize, ref uint offset)
		{
			if (buffer == IntPtr.Zero)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset + 4 > bufferSize)
			{
				return null;
			}
			byte* ptr = (byte*)(void*)buffer + offset;
			ushort num = *(ushort*)ptr;
			ptr += 2;
			if (num == 0)
			{
				return null;
			}
			long num2 = offset + 2 * num + 4;
			if (num2 > bufferSize)
			{
				return null;
			}
			string result = Marshal.PtrToStringUni(new IntPtr(ptr), num);
			offset = (uint)num2;
			return result;
		}

		public static bool IsPrintable(this char ch)
		{
			if (!char.IsControl(ch))
			{
				return !char.IsWhiteSpace(ch);
			}
			return false;
		}

		public static string WithAllWhitespaceStripped(this string str)
		{
			StringBuilder stringBuilder = new StringBuilder();
			foreach (char c in str)
			{
				if (!char.IsWhiteSpace(c))
				{
					stringBuilder.Append(c);
				}
			}
			return stringBuilder.ToString();
		}

		public static bool InvariantEqualsIgnoreCase(this string left, string right)
		{
			if (string.IsNullOrEmpty(left))
			{
				return string.IsNullOrEmpty(right);
			}
			return string.Equals(left, right, StringComparison.InvariantCultureIgnoreCase);
		}

		public static string ExpandTemplateString(string template, Func<string, string> mapFunc)
		{
			if (string.IsNullOrEmpty(template))
			{
				throw new ArgumentNullException("template");
			}
			if (mapFunc == null)
			{
				throw new ArgumentNullException("mapFunc");
			}
			StringBuilder stringBuilder = new StringBuilder();
			int length = template.Length;
			for (int i = 0; i < length; i++)
			{
				char c = template[i];
				if (c != '{')
				{
					stringBuilder.Append(c);
					continue;
				}
				i++;
				int num = i;
				for (; i < length && template[i] != '}'; i++)
				{
				}
				string arg = template.Substring(num, i - num);
				string value = mapFunc(arg);
				stringBuilder.Append(value);
			}
			return stringBuilder.ToString();
		}
	}
	internal struct Substring : IComparable<Substring>, IEquatable<Substring>
	{
		private readonly string m_String;

		private readonly int m_Index;

		private readonly int m_Length;

		public bool isEmpty => m_Length == 0;

		public int length => m_Length;

		public int index => m_Index;

		public char this[int index]
		{
			get
			{
				if (index < 0 || index >= m_Length)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				return m_String[m_Index + index];
			}
		}

		public Substring(string str)
		{
			m_String = str;
			m_Index = 0;
			if (str != null)
			{
				m_Length = str.Length;
			}
			else
			{
				m_Length = 0;
			}
		}

		public Substring(string str, int index, int length)
		{
			m_String = str;
			m_Index = index;
			m_Length = length;
		}

		public Substring(string str, int index)
		{
			m_String = str;
			m_Index = index;
			m_Length = str.Length - index;
		}

		public override bool Equals(object obj)
		{
			if (obj is Substring other)
			{
				return Equals(other);
			}
			if (obj is string other2)
			{
				return Equals(other2);
			}
			return false;
		}

		public bool Equals(string other)
		{
			if (string.IsNullOrEmpty(other))
			{
				return m_Length == 0;
			}
			if (other.Length != m_Length)
			{
				return false;
			}
			for (int i = 0; i < m_Length; i++)
			{
				if (other[i] != m_String[m_Index + i])
				{
					return false;
				}
			}
			return true;
		}

		public bool Equals(Substring other)
		{
			return CompareTo(other) == 0;
		}

		public bool Equals(InternedString other)
		{
			if (length != other.length)
			{
				return false;
			}
			return string.Compare(m_String, m_Index, other.ToString(), 0, length, StringComparison.OrdinalIgnoreCase) == 0;
		}

		public int CompareTo(Substring other)
		{
			return Compare(this, other, StringComparison.CurrentCulture);
		}

		public static int Compare(Substring left, Substring right, StringComparison comparison)
		{
			if (left.m_Length != right.m_Length)
			{
				if (left.m_Length < right.m_Length)
				{
					return -1;
				}
				return 1;
			}
			return string.Compare(left.m_String, left.m_Index, right.m_String, right.m_Index, left.m_Length, comparison);
		}

		public bool StartsWith(string str)
		{
			if (str.Length > length)
			{
				return false;
			}
			for (int i = 0; i < str.Length; i++)
			{
				if (m_String[m_Index + i] != str[i])
				{
					return false;
				}
			}
			return true;
		}

		public string Substr(int index = 0, int length = -1)
		{
			if (length < 0)
			{
				length = this.length - index;
			}
			return m_String.Substring(m_Index + index, length);
		}

		public override string ToString()
		{
			if (m_String == null)
			{
				return string.Empty;
			}
			return m_String.Substring(m_Index, m_Length);
		}

		public override int GetHashCode()
		{
			if (m_String == null)
			{
				return 0;
			}
			if (m_Index == 0 && m_Length == m_String.Length)
			{
				return m_String.GetHashCode();
			}
			return ToString().GetHashCode();
		}

		public static bool operator ==(Substring a, Substring b)
		{
			return a.Equals(b);
		}

		public static bool operator !=(Substring a, Substring b)
		{
			return !a.Equals(b);
		}

		public static bool operator ==(Substring a, InternedString b)
		{
			return a.Equals(b);
		}

		public static bool operator !=(Substring a, InternedString b)
		{
			return !a.Equals(b);
		}

		public static bool operator ==(InternedString a, Substring b)
		{
			return b.Equals(a);
		}

		public static bool operator !=(InternedString a, Substring b)
		{
			return !b.Equals(a);
		}

		public static implicit operator Substring(string s)
		{
			return new Substring(s);
		}
	}
	internal static class TypeHelpers
	{
		public static TObject As<TObject>(this object obj)
		{
			if (obj == null)
			{
				return default(TObject);
			}
			return (TObject)obj;
		}

		public static bool IsInt(this TypeCode type)
		{
			return type switch
			{
				TypeCode.Byte => true, 
				TypeCode.SByte => true, 
				TypeCode.Int16 => true, 
				TypeCode.Int32 => true, 
				TypeCode.Int64 => true, 
				TypeCode.UInt16 => true, 
				TypeCode.UInt32 => true, 
				TypeCode.UInt64 => true, 
				_ => false, 
			};
		}

		public static Type GetValueType(MemberInfo member)
		{
			FieldInfo fieldInfo = member as FieldInfo;
			if (fieldInfo != null)
			{
				return fieldInfo.FieldType;
			}
			PropertyInfo propertyInfo = member as PropertyInfo;
			if (propertyInfo != null)
			{
				return propertyInfo.PropertyType;
			}
			MethodInfo methodInfo = member as MethodInfo;
			if (methodInfo != null)
			{
				return methodInfo.ReturnType;
			}
			return null;
		}

		public static string GetNiceTypeName(this Type type)
		{
			if (type.IsPrimitive)
			{
				if (type == typeof(int))
				{
					return "int";
				}
				if (type == typeof(float))
				{
					return "float";
				}
				if (type == typeof(char))
				{
					return "char";
				}
				if (type == typeof(byte))
				{
					return "byte";
				}
				if (type == typeof(short))
				{
					return "short";
				}
				if (type == typeof(long))
				{
					return "long";
				}
				if (type == typeof(double))
				{
					return "double";
				}
				if (type == typeof(uint))
				{
					return "uint";
				}
				if (type == typeof(sbyte))
				{
					return "sbyte";
				}
				if (type == typeof(ushort))
				{
					return "ushort";
				}
				if (type == typeof(ulong))
				{
					return "ulong";
				}
			}
			return type.Name;
		}

		public static Type GetGenericTypeArgumentFromHierarchy(Type type, Type genericTypeDefinition, int argumentIndex)
		{
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			if (genericTypeDefinition == null)
			{
				throw new ArgumentNullException("genericTypeDefinition");
			}
			if (argumentIndex < 0)
			{
				throw new ArgumentOutOfRangeException("argumentIndex");
			}
			if (genericTypeDefinition.IsInterface)
			{
				while (true)
				{
					Type[] interfaces = type.GetInterfaces();
					bool flag = false;
					Type[] array = interfaces;
					foreach (Type type2 in array)
					{
						if (type2.IsConstructedGenericType && type2.GetGenericTypeDefinition() == genericTypeDefinition)
						{
							type = type2;
							flag = true;
							break;
						}
						Type genericTypeArgumentFromHierarchy = GetGenericTypeArgumentFromHierarchy(type2, genericTypeDefinition, argumentIndex);
						if (genericTypeArgumentFromHierarchy != null)
						{
							return genericTypeArgumentFromHierarchy;
						}
					}
					if (flag)
					{
						break;
					}
					type = type.BaseType;
					if (type == null || type == typeof(object))
					{
						return null;
					}
				}
			}
			else
			{
				while (!type.IsConstructedGenericType || type.GetGenericTypeDefinition() != genericTypeDefinition)
				{
					type = type.BaseType;
					if (type == typeof(object))
					{
						return null;
					}
				}
			}
			return type.GenericTypeArguments[argumentIndex];
		}
	}
	internal struct TypeTable
	{
		public Dictionary<InternedString, Type> table;

		public IEnumerable<string> names => table.Keys.Select((InternedString x) => x.ToString());

		public IEnumerable<InternedString> internedNames => table.Keys;

		public void Initialize()
		{
			table = new Dictionary<InternedString, Type>();
		}

		public InternedString FindNameForType(Type type)
		{
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			foreach (KeyValuePair<InternedString, Type> item in table)
			{
				if (item.Value == type)
				{
					return item.Key;
				}
			}
			return default(InternedString);
		}

		public void AddTypeRegistration(string name, Type type)
		{
			if (string.IsNullOrEmpty(name))
			{
				throw new ArgumentException("Name cannot be null or empty", "name");
			}
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			InternedString key = new InternedString(name);
			table[key] = type;
		}

		public Type LookupTypeRegistration(string name)
		{
			if (string.IsNullOrEmpty(name))
			{
				return null;
			}
			if (table == null)
			{
				throw new InvalidOperationException("Input System not yet initialized");
			}
			InternedString key = new InternedString(name);
			if (table.TryGetValue(key, out var value))
			{
				return value;
			}
			return null;
		}
	}
}
namespace UnityEngine.InputSystem.Composites
{
	[DisplayStringFormat("{negative}/{positive}")]
	[DisplayName("Positive/Negative Binding")]
	public class AxisComposite : InputBindingComposite<float>
	{
		public enum WhichSideWins
		{
			Neither,
			Positive,
			Negative
		}

		[InputControl(layout = "Axis")]
		public int negative;

		[InputControl(layout = "Axis")]
		public int positive;

		[Tooltip("Value to return when the negative side is fully actuated.")]
		public float minValue = -1f;

		[Tooltip("Value to return when the positive side is fully actuated.")]
		public float maxValue = 1f;

		[Tooltip("If both the positive and negative side are actuated, decides what value to return. 'Neither' (default) means that the resulting value is the midpoint between min and max. 'Positive' means that max will be returned. 'Negative' means that min will be returned.")]
		public WhichSideWins whichSideWins;

		public float midPoint => (maxValue + minValue) / 2f;

		public override float ReadValue(ref InputBindingCompositeContext context)
		{
			float num = Mathf.Abs(context.ReadValue<float>(negative));
			float num2 = Mathf.Abs(context.ReadValue<float>(positive));
			bool flag = num > Mathf.Epsilon;
			bool flag2 = num2 > Mathf.Epsilon;
			if (flag == flag2)
			{
				switch (whichSideWins)
				{
				case WhichSideWins.Negative:
					flag2 = false;
					break;
				case WhichSideWins.Positive:
					flag = false;
					break;
				case WhichSideWins.Neither:
					return midPoint;
				}
			}
			float num3 = midPoint;
			if (flag)
			{
				return num3 - (num3 - minValue) * num;
			}
			return num3 + (maxValue - num3) * num2;
		}

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			float num = ReadValue(ref context);
			if (num < midPoint)
			{
				num = Mathf.Abs(num - midPoint);
				return NormalizeProcessor.Normalize(num, 0f, Mathf.Abs(minValue), 0f);
			}
			num = Mathf.Abs(num - midPoint);
			return NormalizeProcessor.Normalize(num, 0f, Mathf.Abs(maxValue), 0f);
		}
	}
	[DesignTimeVisible(false)]
	[DisplayStringFormat("{modifier}+{button}")]
	public class ButtonWithOneModifier : InputBindingComposite<float>
	{
		public enum ModifiersOrder
		{
			Default,
			Ordered,
			Unordered
		}

		[InputControl(layout = "Button")]
		public int modifier;

		[InputControl(layout = "Button")]
		public int button;

		[Tooltip("Obsolete please use modifiers Order. If enabled, this will override the Input Consumption setting, allowing the modifier keys to be pressed after the button and the composite will still trigger.")]
		[Obsolete("Use ModifiersOrder.Unordered with 'modifiersOrder' instead")]
		public bool overrideModifiersNeedToBePressedFirst;

		[Tooltip("By default it follows the Input Consumption setting to determine if the modifers keys need to be pressed first.")]
		public ModifiersOrder modifiersOrder;

		public override float ReadValue(ref InputBindingCompositeContext context)
		{
			if (ModifierIsPressed(ref context))
			{
				return context.ReadValue<float>(button);
			}
			return 0f;
		}

		private bool ModifierIsPressed(ref InputBindingCompositeContext context)
		{
			bool flag = context.ReadValueAsButton(modifier);
			if (flag && modifiersOrder == ModifiersOrder.Ordered)
			{
				double pressTime = context.GetPressTime(button);
				return context.GetPressTime(modifier) <= pressTime;
			}
			return flag;
		}

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			return ReadValue(ref context);
		}

		protected override void FinishSetup(ref InputBindingCompositeContext context)
		{
			if (modifiersOrder == ModifiersOrder.Default)
			{
				if (overrideModifiersNeedToBePressedFirst)
				{
					modifiersOrder = ModifiersOrder.Unordered;
				}
				else
				{
					modifiersOrder = (InputSystem.settings.shortcutKeysConsumeInput ? ModifiersOrder.Ordered : ModifiersOrder.Unordered);
				}
			}
		}
	}
	[DesignTimeVisible(false)]
	[DisplayStringFormat("{modifier1}+{modifier2}+{button}")]
	public class ButtonWithTwoModifiers : InputBindingComposite<float>
	{
		public enum ModifiersOrder
		{
			Default,
			Ordered,
			Unordered
		}

		[InputControl(layout = "Button")]
		public int modifier1;

		[InputControl(layout = "Button")]
		public int modifier2;

		[InputControl(layout = "Button")]
		public int button;

		[Tooltip("Obsolete please use modifiers Order. If enabled, this will override the Input Consumption setting, allowing the modifier keys to be pressed after the button and the composite will still trigger.")]
		[Obsolete("Use ModifiersOrder.Unordered with 'modifiersOrder' instead")]
		public bool overrideModifiersNeedToBePressedFirst;

		[Tooltip("By default it follows the Input Consumption setting to determine if the modifers keys need to be pressed first.")]
		public ModifiersOrder modifiersOrder;

		public override float ReadValue(ref InputBindingCompositeContext context)
		{
			if (ModifiersArePressed(ref context))
			{
				return context.ReadValue<float>(button);
			}
			return 0f;
		}

		private bool ModifiersArePressed(ref InputBindingCompositeContext context)
		{
			bool flag = context.ReadValueAsButton(modifier1) && context.ReadValueAsButton(modifier2);
			if (flag && modifiersOrder == ModifiersOrder.Ordered)
			{
				double pressTime = context.GetPressTime(button);
				double pressTime2 = context.GetPressTime(modifier1);
				double pressTime3 = context.GetPressTime(modifier2);
				if (pressTime2 <= pressTime)
				{
					return pressTime3 <= pressTime;
				}
				return false;
			}
			return flag;
		}

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			return ReadValue(ref context);
		}

		protected override void FinishSetup(ref InputBindingCompositeContext context)
		{
			if (modifiersOrder == ModifiersOrder.Default)
			{
				if (overrideModifiersNeedToBePressedFirst)
				{
					modifiersOrder = ModifiersOrder.Unordered;
				}
				else
				{
					modifiersOrder = (InputSystem.settings.shortcutKeysConsumeInput ? ModifiersOrder.Ordered : ModifiersOrder.Unordered);
				}
			}
		}
	}
	[DisplayStringFormat("{modifier}+{binding}")]
	[DisplayName("Binding With One Modifier")]
	public class OneModifierComposite : InputBindingComposite
	{
		public enum ModifiersOrder
		{
			Default,
			Ordered,
			Unordered
		}

		[InputControl(layout = "Button")]
		public int modifier;

		[InputControl]
		public int binding;

		[Tooltip("Obsolete please use modifiers Order. If enabled, this will override the Input Consumption setting, allowing the modifier keys to be pressed after the button and the composite will still trigger.")]
		[Obsolete("Use ModifiersOrder.Unordered with 'modifiersOrder' instead")]
		public bool overrideModifiersNeedToBePressedFirst;

		[Tooltip("By default it follows the Input Consumption setting to determine if the modifers keys need to be pressed first.")]
		public ModifiersOrder modifiersOrder;

		private int m_ValueSizeInBytes;

		private Type m_ValueType;

		private bool m_BindingIsButton;

		public override Type valueType => m_ValueType;

		public override int valueSizeInBytes => m_ValueSizeInBytes;

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			if (ModifierIsPressed(ref context))
			{
				return context.EvaluateMagnitude(binding);
			}
			return 0f;
		}

		public unsafe override void ReadValue(ref InputBindingCompositeContext context, void* buffer, int bufferSize)
		{
			if (ModifierIsPressed(ref context))
			{
				context.ReadValue(binding, buffer, bufferSize);
			}
			else
			{
				UnsafeUtility.MemClear(buffer, m_ValueSizeInBytes);
			}
		}

		private bool ModifierIsPressed(ref InputBindingCompositeContext context)
		{
			bool flag = context.ReadValueAsButton(modifier);
			if (flag && m_BindingIsButton && modifiersOrder == ModifiersOrder.Ordered)
			{
				double pressTime = context.GetPressTime(binding);
				return context.GetPressTime(modifier) <= pressTime;
			}
			return flag;
		}

		protected override void FinishSetup(ref InputBindingCompositeContext context)
		{
			DetermineValueTypeAndSize(ref context, binding, out m_ValueType, out m_ValueSizeInBytes, out m_BindingIsButton);
			if (modifiersOrder == ModifiersOrder.Default)
			{
				if (overrideModifiersNeedToBePressedFirst)
				{
					modifiersOrder = ModifiersOrder.Unordered;
				}
				else
				{
					modifiersOrder = (InputSystem.settings.shortcutKeysConsumeInput ? ModifiersOrder.Ordered : ModifiersOrder.Unordered);
				}
			}
		}

		public override object ReadValueAsObject(ref InputBindingCompositeContext context)
		{
			if (context.ReadValueAsButton(modifier))
			{
				return context.ReadValueAsObject(binding);
			}
			return null;
		}

		internal static void DetermineValueTypeAndSize(ref InputBindingCompositeContext context, int part, out Type valueType, out int valueSizeInBytes, out bool isButton)
		{
			valueSizeInBytes = 0;
			isButton = true;
			Type type = null;
			foreach (InputBindingCompositeContext.PartBinding control in context.controls)
			{
				if (control.part == part)
				{
					Type type2 = control.control.valueType;
					if (type == null || type2.IsAssignableFrom(type))
					{
						type = type2;
					}
					else if (!type.IsAssignableFrom(type2))
					{
						type = typeof(Object);
					}
					valueSizeInBytes = Math.Max(control.control.valueSizeInBytes, valueSizeInBytes);
					isButton &= control.control.isButton;
				}
			}
			valueType = type;
		}
	}
	[DisplayStringFormat("{modifier1}+{modifier2}+{binding}")]
	[DisplayName("Binding With Two Modifiers")]
	public class TwoModifiersComposite : InputBindingComposite
	{
		public enum ModifiersOrder
		{
			Default,
			Ordered,
			Unordered
		}

		[InputControl(layout = "Button")]
		public int modifier1;

		[InputControl(layout = "Button")]
		public int modifier2;

		[InputControl]
		public int binding;

		[Tooltip("Obsolete please use modifiers Order. If enabled, this will override the Input Consumption setting, allowing the modifier keys to be pressed after the button and the composite will still trigger.")]
		[Obsolete("Use ModifiersOrder.Unordered with 'modifiersOrder' instead")]
		public bool overrideModifiersNeedToBePressedFirst;

		[Tooltip("By default it follows the Input Consumption setting to determine if the modifers keys need to be pressed first.")]
		public ModifiersOrder modifiersOrder;

		private int m_ValueSizeInBytes;

		private Type m_ValueType;

		private bool m_BindingIsButton;

		public override Type valueType => m_ValueType;

		public override int valueSizeInBytes => m_ValueSizeInBytes;

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			if (ModifiersArePressed(ref context))
			{
				return context.EvaluateMagnitude(binding);
			}
			return 0f;
		}

		public unsafe override void ReadValue(ref InputBindingCompositeContext context, void* buffer, int bufferSize)
		{
			if (ModifiersArePressed(ref context))
			{
				context.ReadValue(binding, buffer, bufferSize);
			}
			else
			{
				UnsafeUtility.MemClear(buffer, m_ValueSizeInBytes);
			}
		}

		private bool ModifiersArePressed(ref InputBindingCompositeContext context)
		{
			bool flag = context.ReadValueAsButton(modifier1) && context.ReadValueAsButton(modifier2);
			if (flag && m_BindingIsButton && modifiersOrder == ModifiersOrder.Ordered)
			{
				double pressTime = context.GetPressTime(binding);
				double pressTime2 = context.GetPressTime(modifier1);
				double pressTime3 = context.GetPressTime(modifier2);
				if (pressTime2 <= pressTime)
				{
					return pressTime3 <= pressTime;
				}
				return false;
			}
			return flag;
		}

		protected override void FinishSetup(ref InputBindingCompositeContext context)
		{
			OneModifierComposite.DetermineValueTypeAndSize(ref context, binding, out m_ValueType, out m_ValueSizeInBytes, out m_BindingIsButton);
			if (modifiersOrder == ModifiersOrder.Default)
			{
				if (overrideModifiersNeedToBePressedFirst)
				{
					modifiersOrder = ModifiersOrder.Unordered;
				}
				else
				{
					modifiersOrder = (InputSystem.settings.shortcutKeysConsumeInput ? ModifiersOrder.Ordered : ModifiersOrder.Unordered);
				}
			}
		}

		public override object ReadValueAsObject(ref InputBindingCompositeContext context)
		{
			if (context.ReadValueAsButton(modifier1) && context.ReadValueAsButton(modifier2))
			{
				return context.ReadValueAsObject(binding);
			}
			return null;
		}
	}
	[DisplayStringFormat("{up}/{left}/{down}/{right}")]
	[DisplayName("Up/Down/Left/Right Composite")]
	public class Vector2Composite : InputBindingComposite<Vector2>
	{
		public enum Mode
		{
			Analog = 2,
			DigitalNormalized = 0,
			Digital = 1
		}

		[InputControl(layout = "Axis")]
		public int up;

		[InputControl(layout = "Axis")]
		public int down;

		[InputControl(layout = "Axis")]
		public int left;

		[InputControl(layout = "Axis")]
		public int right;

		[Obsolete("Use Mode.DigitalNormalized with 'mode' instead")]
		public bool normalize = true;

		public Mode mode;

		public override Vector2 ReadValue(ref InputBindingCompositeContext context)
		{
			Mode mode = this.mode;
			if (mode == Mode.Analog)
			{
				float num = context.ReadValue<float>(up);
				float num2 = context.ReadValue<float>(down);
				float num3 = context.ReadValue<float>(left);
				float num4 = context.ReadValue<float>(right);
				return DpadControl.MakeDpadVector(num, num2, num3, num4);
			}
			bool num5 = context.ReadValueAsButton(up);
			bool flag = context.ReadValueAsButton(down);
			bool flag2 = context.ReadValueAsButton(left);
			bool flag3 = context.ReadValueAsButton(right);
			if (!normalize)
			{
				mode = Mode.Digital;
			}
			return DpadControl.MakeDpadVector(num5, flag, flag2, flag3, mode == Mode.DigitalNormalized);
		}

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			return ReadValue(ref context).magnitude;
		}
	}
	[DisplayStringFormat("{up}+{down}/{left}+{right}/{forward}+{backward}")]
	[DisplayName("Up/Down/Left/Right/Forward/Backward Composite")]
	public class Vector3Composite : InputBindingComposite<Vector3>
	{
		public enum Mode
		{
			Analog,
			DigitalNormalized,
			Digital
		}

		[InputControl(layout = "Axis")]
		public int up;

		[InputControl(layout = "Axis")]
		public int down;

		[InputControl(layout = "Axis")]
		public int left;

		[InputControl(layout = "Axis")]
		public int right;

		[InputControl(layout = "Axis")]
		public int forward;

		[InputControl(layout = "Axis")]
		public int backward;

		public Mode mode;

		public override Vector3 ReadValue(ref InputBindingCompositeContext context)
		{
			if (mode == Mode.Analog)
			{
				float num = context.ReadValue<float>(up);
				float num2 = context.ReadValue<float>(down);
				float num3 = context.ReadValue<float>(left);
				float num4 = context.ReadValue<float>(right);
				float num5 = context.ReadValue<float>(forward);
				float num6 = context.ReadValue<float>(backward);
				return new Vector3(num4 - num3, num - num2, num5 - num6);
			}
			float num7 = (context.ReadValueAsButton(up) ? 1f : 0f);
			float num8 = (context.ReadValueAsButton(down) ? (-1f) : 0f);
			float num9 = (context.ReadValueAsButton(left) ? (-1f) : 0f);
			float num10 = (context.ReadValueAsButton(right) ? 1f : 0f);
			float num11 = (context.ReadValueAsButton(forward) ? 1f : 0f);
			float num12 = (context.ReadValueAsButton(backward) ? (-1f) : 0f);
			Vector3 result = new Vector3(num9 + num10, num7 + num8, num11 + num12);
			if (mode == Mode.DigitalNormalized)
			{
				return result.normalized;
			}
			return result;
		}

		public override float EvaluateMagnitude(ref InputBindingCompositeContext context)
		{
			return ReadValue(ref context).magnitude;
		}
	}
}
